globalThis.__BQ = {"meristem":{"ilkokul":{"kolay":[{"q":"Bitkilerde sürekli bölünebilen ve büyümeyi sağlayan genç hücre topluluğuna ne ad verilir?","steps":[{"t":"Görevi düşün","a":"Büyümeyi sağlar","d":"Bir bitkinin boyca uzaması ve enine kalınlaşması için yeni hücreler üretilmesi gerekir. Bu yeni hücreleri üreten özel bir doku vardır."},{"t":"Doku adını bul","a":"Sürgen doku","d":"Sürekli bölünerek yeni hücreler oluşturan bu dokuya meristem yani sürgen doku denir. Bitkinin büyümesini sağlayan ana dokudur."}],"ans":"Meristem (sürgen) doku"},{"q":"Bir bitkinin boyca uzaması, kök ve gövde uçlarındaki hangi dokunun çalışmasıyla olur?","steps":[{"t":"Boyca uzamayı düşün","a":"Uçlarda olur","d":"Bitkiler kök ve gövdelerinin en uç kısımlarından boyca uzar. Bu uçlarda bölünen genç hücreler bulunur."},{"t":"Dokuyu söyle","a":"Uç meristem","d":"Kök ve gövde uçlarındaki sürgen dokuya uç (apikal) meristem denir. Bu doku bölünerek bitkiyi boyca uzatır."}],"ans":"Uç (apikal) meristem"},{"q":"Meristem hücreleri bölünerek sürekli ne üretir?","steps":[{"t":"Bölünmeyi düşün","a":"Hücre artar","d":"Bir hücre ikiye bölünürse iki hücre olur. Meristem hücreleri durmadan bölünür."},{"t":"Sonucu bul","a":"Yeni hücreler","d":"Meristem hücrelerinin bölünmesiyle bitkide sürekli yeni hücreler oluşur. Bu yeni hücreler bitkinin büyümesini sağlar."}],"ans":"Yeni hücreler"},{"q":"Bir ağacın her yıl biraz daha uzaması, hangi dokunun durmadan çalışmasının sonucudur?","steps":[{"t":"Uzamayı düşün","a":"Her yıl artar","d":"Ağaçlar yıldan yıla daha uzun olur. Bu uzama kendiliğinden değil, özel hücrelerin çalışmasıyla olur."},{"t":"Dokuyu bul","a":"Sürgen doku","d":"Ağacın boyca uzaması meristem yani sürgen dokunun sürekli bölünmesiyle olur. Bu doku durmadan yeni hücre üretir."}],"ans":"Meristem (sürgen) doku"},{"q":"Meristem hücreleri genç mi yoksa yaşlı hücreler midir?","steps":[{"t":"Görevi hatırla","a":"Hep bölünür","d":"Meristem hücreleri sürekli bölünebilen hücrelerdir. Sürekli bölünme yeteneği genç hücrelerin özelliğidir."},{"t":"Cevabı ver","a":"Genç hücreler","d":"Meristem hücreleri genç hücrelerdir. Bu yüzden bölünme yetenekleri çok yüksektir."}],"ans":"Genç hücreler"}],"zor":[{"q":"Meristem hücrelerinin çeperi neden ince olur ve bu durum bölünmeye nasıl yardım eder?","steps":[{"t":"Çeperi düşün","a":"İnce çeper","d":"Meristem hücrelerinin etrafını saran çeper kalın değil incedir. Kalın çeper hücrenin bölünmesini zorlaştırırdı."},{"t":"Bölünmeye etkisi","a":"Kolay bölünür","d":"İnce çeper sayesinde hücre kolayca bölünebilir ve şekil değiştirebilir. Bu yüzden meristem hücreleri durmadan bölünebilir."}],"ans":"İnce çeper kolay bölünmeyi sağlar"},{"q":"Bitkide hem boyca uzamayı hem de enine kalınlaşmayı sağlayan iki çeşit sürgen doku vardır. Bunlar nelerdir?","steps":[{"t":"Boyca büyümeyi düşün","a":"Uç meristem","d":"Bitkinin uçlarındaki sürgen doku boyca uzamayı sağlar. Buna uç meristem denir."},{"t":"Enine büyümeyi düşün","a":"Yanal meristem","d":"Gövdenin kalınlaşmasını sağlayan yandaki sürgen dokuya yanal meristem denir. İki meristem birlikte çalışır."},{"t":"İkisini birleştir","a":"Uç ve yanal","d":"Boyca uzamayı uç meristem, enine kalınlaşmayı yanal meristem sağlar. Bu iki doku bitkinin büyümesini birlikte yönetir."}],"ans":"Uç (apikal) meristem ve yanal (lateral) meristem"},{"q":"Bir ağacın gövdesinin yıllar içinde kalınlaşması hangi tür meristemin çalışmasıyla olur?","steps":[{"t":"Kalınlaşmayı düşün","a":"Enine büyüme","d":"Ağacın gövdesi her yıl biraz daha kalınlaşır. Bu enine bir büyümedir."},{"t":"Dokuyu bul","a":"Yanal meristem","d":"Enine kalınlaşmayı gövdenin yanında bulunan yanal (lateral) meristem sağlar. Bu doku gövdeyi şişkinleştirir."}],"ans":"Yanal (lateral) meristem"},{"q":"Meristem hücrelerinde büyük su kofulu neden bulunmaz?","steps":[{"t":"Genç hücreyi düşün","a":"Yeni hücre","d":"Meristem hücreleri çok genç ve yeni oluşmuş hücrelerdir. Bu hücreler henüz olgunlaşmamıştır."},{"t":"Koful durumu","a":"Kofulsuz","d":"Genç oldukları için içlerinde büyük su kofulu oluşmamıştır. Büyük koful daha çok yaşlı hücrelerde bulunur."}],"ans":"Genç oldukları için kofulsuzdur"},{"q":"Bir saksı bitkisinin tepe sürgününü kopardığımızda boyca uzamasının yavaşlaması neyi gösterir?","steps":[{"t":"Tepeyi düşün","a":"Uç kısım","d":"Bitkinin tepesindeki sürgün uç kısımdır. Boyca uzamayı sağlayan hücreler burada bulunur."},{"t":"Sonucu yorumla","a":"Uç meristem önemli","d":"Tepeyi kopardığımızda uç meristemi kaldırmış oluruz. Bu yüzden boyca uzama yavaşlar, demek ki uzamayı uç meristem sağlar."}],"ans":"Boyca uzamayı uç meristemin sağladığını"}]},"ortaokul":{"kolay":[{"q":"Meristem dokusunun bitki büyümesindeki temel görevi nedir?","steps":[{"t":"Bölünmeyi hatırla","a":"Sürekli bölünür","d":"Meristem hücreleri sürekli olarak mitoz bölünme geçirir. Bu sayede sayıları durmadan artar."},{"t":"Görevi belirle","a":"Büyüme sağlar","d":"Bölünen hücreler bitkinin büyümesini sağlar. Meristemin temel görevi bitkiyi büyütmektir."}],"ans":"Sürekli bölünerek bitkinin büyümesini sağlar"},{"q":"Birincil meristem bitkide hangi yönde büyümeyi sağlar?","steps":[{"t":"Birincil meristemi bul","a":"Uçlarda yer alır","d":"Birincil (apikal) meristem kök ve gövde uçlarında bulunur. Buralarda hücreler hızla bölünür."},{"t":"Yönü belirle","a":"Boyca büyüme","d":"Uçlardaki bu bölünme bitkiyi boyca uzatır. Yani birincil meristem boyca büyümeyi sağlar."}],"ans":"Boyca (uzunlamasına) büyümeyi sağlar"},{"q":"İkincil meristem bitkide hangi değişikliği sağlar?","steps":[{"t":"İkincil meristemi bul","a":"Yanal yerleşir","d":"İkincil (lateral) meristem gövde ve kökün yanal bölgelerinde bulunur. Kambiyum bu dokuya örnektir."},{"t":"Sonucu belirle","a":"Enine kalınlaşma","d":"Yanal yerleşimli bu doku gövdenin enine kalınlaşmasını sağlar. Ağaçların gövdesi bu sayede yıldan yıla kalınlaşır."}],"ans":"Enine kalınlaşmayı sağlar"},{"q":"Kambiyum hangi meristem türüne örnektir?","steps":[{"t":"Kambiyumu düşün","a":"Yanal konumda","d":"Kambiyum gövdede yanal olarak yerleşmiş bir meristem dokusudur. Odun ve soymuk arasında bulunur."},{"t":"Türünü belirle","a":"İkincil meristem","d":"Yanal yerleşimi ve enine kalınlaşma görevi nedeniyle kambiyum ikincil meristemdir. Birincil meristemden sonra oluşur."}],"ans":"İkincil (yanal) meristem"},{"q":"Meristem hücrelerinin sitoplazması neden boldur?","steps":[{"t":"Bölünmeyi hatırla","a":"Çok bölünür","d":"Meristem hücreleri sürekli bölünür ve bunun için bol miktarda yapı malzemesine ihtiyaç duyar. Sitoplazma bu malzemeyi içerir."},{"t":"Sonucu belirle","a":"Bol sitoplazma","d":"Sürekli bölünme için bol sitoplazma gerekir. Bu yüzden meristem hücreleri sitoplazmaca zengindir."}],"ans":"Sürekli bölündükleri için bol sitoplazmalıdır"}],"zor":[{"q":"Birincil ve ikincil meristemin konum ve görev bakımından farkı nedir?","steps":[{"t":"Birincili tanımla","a":"Uçta, boyca","d":"Birincil meristem kök ve gövde uçlarında yer alır ve boyca büyümeyi sağlar. Apikal meristem de denir."},{"t":"İkincili tanımla","a":"Yanda, enine","d":"İkincil meristem yanal konumdadır ve enine kalınlaşmayı sağlar. Kambiyum buna örnektir."},{"t":"Farkı özetle","a":"Konum ve yön farkı","d":"Birincil uçta olup boyca, ikincil yanda olup enine büyütür. İki meristem farklı yönlerde büyüme sağlar."}],"ans":"Birincil uçta boyca, ikincil yanda enine büyümeyi sağlar"},{"q":"Bir bitkide hem birincil hem ikincil meristem birlikte çalıştığında bitkinin görünümü nasıl değişir?","steps":[{"t":"Birincilin etkisi","a":"Uzar","d":"Birincil meristem boyca büyüme sağladığı için bitki uzar. Kök ve gövde uçtan büyür."},{"t":"İkincilin etkisi","a":"Kalınlaşır","d":"İkincil meristem enine kalınlaşma sağladığı için gövde kalınlaşır. Odunsu bitkilerde belirgindir."},{"t":"Birlikte sonuç","a":"Uzar ve kalınlaşır","d":"İki meristem birlikte çalıştığında bitki hem uzar hem kalınlaşır. Böylece ağaçlar büyük ve sağlam bir yapıya ulaşır."}],"ans":"Bitki hem boyca uzar hem enine kalınlaşır"},{"q":"Otsu bir bitkide gövde neden odunsu bir ağaç kadar kalınlaşmaz?","steps":[{"t":"Otsu yapıyı düşün","a":"Yumuşak gövde","d":"Otsu bitkilerin gövdesi yumuşak ve ince kalır. Bu bitkiler genellikle bir mevsim yaşar."},{"t":"İkincil meristemi düşün","a":"Zayıf veya yok","d":"Otsu bitkilerde ikincil meristem (kambiyum) gelişmemiştir ya da çok azdır. Enine kalınlaşmayı sağlayan doku yetersizdir."},{"t":"Sonucu çıkar","a":"Az kalınlaşma","d":"İkincil meristem yetersiz olduğu için enine kalınlaşma az olur. Bu yüzden otsu bitkiler ağaç gibi kalınlaşmaz."}],"ans":"İkincil meristem (kambiyum) gelişmediği için"},{"q":"Meristem hücrelerinin ince çeperli, bol sitoplazmalı ve kofulsuz olması bölünmeye nasıl katkı sağlar?","steps":[{"t":"İnce çeperi düşün","a":"Esnek yapı","d":"İnce çeper hücrenin kolayca bölünmesine ve şekil değiştirmesine izin verir. Kalın çeper bölünmeyi engellerdi."},{"t":"Sitoplazma ve koful","a":"Bol malzeme","d":"Bol sitoplazma bölünme için gereken malzemeyi sağlar, koful yokluğu ise yer açar. Büyük koful bölünmeyi zorlaştırırdı."},{"t":"Sonucu birleştir","a":"Hızlı bölünme","d":"Bu üç özellik birlikte hücrenin hızlı ve sürekli bölünmesini sağlar. Meristemin yapısı bölünmeye uygundur."}],"ans":"Yapısı sürekli ve hızlı bölünmeye uygun olduğu için"},{"q":"Tepe sürgünü koparılan bir bitkide yan dalların gelişmesi neyi gösterir?","steps":[{"t":"Tepe etkisini düşün","a":"Tepe baskısı","d":"Tepe sürgünündeki uç meristem yan tomurcukların gelişmesini baskılar. Bu duruma apikal baskınlık denir."},{"t":"Tepe kalkınca","a":"Baskı kalkar","d":"Tepe koparılınca uç meristemin baskısı ortadan kalkar. Yan tomurcuklar serbest kalır."},{"t":"Sonucu yorumla","a":"Yan dallar gelişir","d":"Baskı kalkınca yan tomurcuklardaki meristemler etkinleşir ve yan dallar gelişir. Bu, uç meristemin yan dalları kontrol ettiğini gösterir."}],"ans":"Uç meristemin yan dalların gelişimini baskıladığını"}]},"lise":{"kolay":[{"q":"Meristem (sürgen) dokunun tanımını ve temel işlevini açıklayınız.","steps":[{"t":"Hücre özelliği","a":"Bölünebilir hücreler","d":"Meristem, bölünme yeteneğini koruyan genç hücrelerden oluşan bir dokudur. Bu hücreler farklılaşmamıştır."},{"t":"Temel işlev","a":"Büyüme ve yenilenme","d":"Meristem mitoz bölünme ile yeni hücreler üreterek bitkinin büyümesini sağlar. Ayrıca diğer dokuların kaynağıdır."}],"ans":"Sürekli bölünerek büyümeyi sağlayan farklılaşmamış genç doku"},{"q":"Birincil (apikal) meristemin bulunduğu yerleri ve işlevini açıklayınız.","steps":[{"t":"Konum","a":"Kök ve gövde ucu","d":"Birincil meristem kök ucunda ve gövde ucunda (tomurcuklarda) bulunur. Bu bölgeler büyüme noktalarıdır."},{"t":"İşlev","a":"Boyca uzama","d":"Apikal meristem boyca (uzunlamasına) büyümeyi sağlar. Bitkinin kök ve gövdesini uzatır."}],"ans":"Kök ve gövde uçlarında bulunur, boyca büyümeyi sağlar"},{"q":"İkincil (lateral) meristemin konumunu ve işlevini açıklayınız.","steps":[{"t":"Konum","a":"Yanal yerleşim","d":"İkincil meristem gövde ve kökün yanal bölgelerinde bulunur. Kambiyum ve mantar kambiyumu örnektir."},{"t":"İşlev","a":"Enine kalınlaşma","d":"Lateral meristem enine kalınlaşmayı sağlar. Odunsu bitkilerde gövdenin kalınlaşmasından sorumludur."}],"ans":"Yanal konumda bulunur, enine kalınlaşmayı sağlar"},{"q":"Meristem hücrelerinin yapısal özelliklerini (çeper, sitoplazma, koful, çekirdek) sıralayınız.","steps":[{"t":"Çeper ve koful","a":"İnce çeper, kofulsuz","d":"Meristem hücreleri ince çeperlidir ve belirgin büyük kofulları yoktur. Bu özellikler bölünmeyi kolaylaştırır."},{"t":"Sitoplazma ve çekirdek","a":"Bol sitoplazma, büyük çekirdek","d":"Sitoplazmaları boldur ve çekirdekleri hücreye göre büyüktür. Bu yapı yoğun bölünme etkinliğini destekler."}],"ans":"İnce çeperli, kofulsuz, bol sitoplazmalı, büyük çekirdekli"},{"q":"Kambiyumun hangi meristem türü olduğunu ve görevini açıklayınız.","steps":[{"t":"Tür","a":"İkincil meristem","d":"Kambiyum yanal konumda bulunan bir ikincil meristem dokusudur. Odun ve soymuk arasında yer alır."},{"t":"Görev","a":"Enine büyüme","d":"Kambiyum içe doğru odun (ksilem), dışa doğru soymuk (floem) üreterek gövdeyi kalınlaştırır. Yıllık halkalar bu etkinliğin sonucudur."}],"ans":"İkincil meristemdir, enine kalınlaşmayı (odun ve soymuk üretimi) sağlar"},{"q":"Meristem hücrelerinin bölünme şeklini ve sonucunu açıklayınız.","steps":[{"t":"Bölünme şekli","a":"Mitoz","d":"Meristem hücreleri mitoz bölünme geçirir. Bu bölünmede oluşan hücreler ana hücreyle aynı kromozom sayısına sahiptir."},{"t":"Sonuç","a":"Hücre artışı","d":"Mitozla hücre sayısı artar ve bunların bir kısmı farklılaşarak diğer dokuları oluşturur. Bir kısmı ise meristem olarak kalır."}],"ans":"Mitozla bölünür, hücre sayısını artırır ve doku oluşturur"},{"q":"Birincil meristemin kökenini (embriyonik doku) kısaca açıklayınız.","steps":[{"t":"Köken","a":"Embriyodan gelir","d":"Birincil meristem tohumdaki embriyodan köken alır. Embriyonik dokunun bölünme yeteneğini korumuş kısmıdır."},{"t":"Sonuç","a":"Uç meristem","d":"Bu doku kök ve gövde uçlarında uç meristem olarak yer alır. Bitkinin ilk büyümesini sağlar."}],"ans":"Embriyonik dokudan köken alır, uç meristemi oluşturur"},{"q":"Meristem dokunun bitkide hangi diğer dokuların kaynağı olduğunu açıklayınız.","steps":[{"t":"Farklılaşma","a":"Hücre özelleşir","d":"Meristem hücrelerinin bir kısmı bölündükten sonra farklılaşır. Farklılaşan hücreler özel görevler kazanır."},{"t":"Sonuç","a":"Sürekli dokular","d":"Bu farklılaşma ile parankima, iletim, destek ve örtü gibi sürekli dokular oluşur. Meristem tüm bu dokuların kaynağıdır."}],"ans":"Parankima, iletim, destek ve örtü gibi sürekli dokuların kaynağıdır"},{"q":"Uç meristem ile yanal meristemin sağladığı büyüme türlerini karşılaştırınız.","steps":[{"t":"Uç meristem","a":"Boyca","d":"Uç (apikal) meristem boyca (primer) büyüme sağlar. Bitkinin uzamasından sorumludur."},{"t":"Yanal meristem","a":"Enine","d":"Yanal (lateral) meristem enine (sekonder) büyüme sağlar. Gövdenin kalınlaşmasından sorumludur."}],"ans":"Uç meristem boyca, yanal meristem enine büyümeyi sağlar"},{"q":"Meristem hücrelerinin farklılaşmamış olmasının önemini açıklayınız.","steps":[{"t":"Farklılaşmamayı düşün","a":"Özelleşmemiş","d":"Meristem hücreleri belirli bir göreve özelleşmemiştir. Bu yüzden her tür dokuya dönüşebilir."},{"t":"Önemini belirle","a":"Çok yönlü","d":"Farklılaşmamış olmaları sayesinde ihtiyaca göre farklı dokulara dönüşebilirler. Bu durum bitkinin büyüme ve onarımı için önemlidir."}],"ans":"Her tür dokuya dönüşebildikleri için büyüme ve onarımı sağlar"},{"q":"Mantar kambiyumunun (fellojen) hangi meristem türü olduğunu ve görevini açıklayınız.","steps":[{"t":"Tür","a":"İkincil meristem","d":"Mantar kambiyumu (fellojen) yanal yerleşimli bir ikincil meristemdir. Gövde ve kökün dış kısımlarında oluşur."},{"t":"Görev","a":"Mantar doku üretir","d":"Fellojen dışa doğru mantar dokusu üreterek bitkinin dış yüzeyini korur. Bu mantar doku su kaybını ve zararlıları engeller."}],"ans":"İkincil meristemdir, koruyucu mantar dokusunu üretir"},{"q":"Bir tohum çimlenirken meristem dokusunun rolünü açıklayınız.","steps":[{"t":"Çimlenmeyi düşün","a":"Embriyo gelişir","d":"Tohum çimlenirken embriyodaki hücreler bölünmeye başlar. Bu bölünen hücreler meristematiktir."},{"t":"Rolü belirle","a":"Büyüme başlatır","d":"Meristem dokusu bölünerek kök ve gövdenin oluşmasını ve uzamasını sağlar. Böylece fide gelişmeye başlar."}],"ans":"Bölünerek kök ve gövdenin oluşup uzamasını sağlar"},{"q":"Meristem dokusunun yara onarımındaki rolünü açıklayınız.","steps":[{"t":"Yarayı düşün","a":"Doku zedelenir","d":"Bitki bir yerinden yaralandığında o bölgedeki dokular zarar görür. Onarım için yeni hücreler gerekir."},{"t":"Rolü belirle","a":"Yeni hücre üretir","d":"Yakındaki hücreler meristematik özellik kazanıp bölünerek yarayı kapatır. Böylece meristem benzeri etkinlik onarımı sağlar."}],"ans":"Bölünerek yeni hücre üretip yarayı kapatır"},{"q":"Birincil büyüme ile ikincil büyüme arasındaki temel farkı açıklayınız.","steps":[{"t":"Birincil büyüme","a":"Boyca","d":"Birincil büyüme apikal meristemle olur ve bitkiyi boyca uzatır. Tüm bitkilerde görülür."},{"t":"İkincil büyüme","a":"Enine","d":"İkincil büyüme lateral meristemle olur ve gövdeyi enine kalınlaştırır. Daha çok odunsu bitkilerde belirgindir."}],"ans":"Birincil büyüme boyca, ikincil büyüme enine olur"},{"q":"Meristem hücrelerinin büyük çekirdekli olmasının nedenini açıklayınız.","steps":[{"t":"Bölünmeyi düşün","a":"Yoğun etkinlik","d":"Meristem hücreleri sürekli bölünür ve bu süreçte DNA sürekli kullanılır. Çekirdek bu etkinliği yönetir."},{"t":"Çekirdek ilişkisi","a":"Büyük çekirdek","d":"Yoğun bölünme ve protein sentezi için büyük ve etkin bir çekirdek gerekir. Bu yüzden meristem hücreleri büyük çekirdeklidir."}],"ans":"Yoğun bölünme ve sentez etkinliği için büyük çekirdeklidir"}],"zor":[{"q":"Bir odunsu ağacın gövdesinde gözlenen yıllık halkaların oluşumunu kambiyum etkinliğiyle açıklayınız.","steps":[{"t":"Kambiyumu hatırla","a":"İkincil meristem","d":"Kambiyum gövdede yanal yerleşimli bir ikincil meristemdir. İçe doğru odun (ksilem) üretir."},{"t":"Mevsim etkisi","a":"İlkbahar ve yaz odunu","d":"İlkbaharda kambiyum geniş hücreli açık renk odun, yaz sonunda dar hücreli koyu renk odun üretir. Bu renk farkı bir halka oluşturur."},{"t":"Halka sayısını yorumla","a":"Yaş hesabı","d":"Her yıl bir açık-koyu çift halka oluşur ve halka sayısı ağacın yaşını verir. Böylece kambiyum etkinliği yıllık halkaları meydana getirir."}],"ans":"Kambiyumun mevsimsel farklı odun üretmesiyle yıllık halkalar oluşur"},{"q":"Apikal baskınlık olayını uç meristemin hormonal etkisiyle açıklayınız.","steps":[{"t":"Uç meristemi düşün","a":"Oksin üretir","d":"Uç meristem oksin adı verilen bir büyüme hormonu üretir. Bu hormon aşağı doğru taşınır."},{"t":"Baskının nedeni","a":"Yan tomurcuk baskısı","d":"Yüksek oksin derişimi yan tomurcukların gelişmesini baskılar. Bu yüzden bitki yanlara değil yukarıya doğru büyür."},{"t":"Uç koparılırsa","a":"Baskı kalkar","d":"Uç koparıldığında oksin kaynağı kalkar ve yan tomurcuklar gelişir. Bu olaya apikal baskınlık denir."}],"ans":"Uç meristemin ürettiği oksinin yan tomurcukları baskılamasıyla"},{"q":"Birincil ve ikincil meristemin kökeni bakımından farkını (embriyonik ve sonradan kazanılmış) açıklayınız.","steps":[{"t":"Birincilin kökeni","a":"Embriyonik","d":"Birincil meristem doğrudan embriyodaki bölünme yeteneğini koruyan hücrelerden gelir. Bu yüzden gerçek (primer) meristem sayılır."},{"t":"İkincilin kökeni","a":"Farklılaşmış hücreden","d":"İkincil meristem ise olgun, farklılaşmış parankima hücrelerinin yeniden bölünme yeteneği kazanmasıyla oluşur. Kambiyum buna örnektir."},{"t":"Farkı özetle","a":"Köken farkı","d":"Birincil meristem embriyonik kökenliyken ikincil meristem sonradan kazanılır. Bu temel köken farkıdır."}],"ans":"Birincil embriyonik kökenli, ikincil farklılaşmış hücrelerden sonradan oluşur"},{"q":"Tek çenekli bitkilerin çoğunun neden belirgin ikincil kalınlaşma göstermediğini meristem yapısıyla açıklayınız.","steps":[{"t":"Tek çenekliyi düşün","a":"Dağınık iletim demeti","d":"Tek çenekli bitkilerde iletim demetleri gövdede dağınık yerleşmiştir. Bu demetler arasında düzenli bir kambiyum halkası yoktur."},{"t":"Kambiyum eksikliği","a":"Yanal meristem yok","d":"Düzenli bir lateral meristem (kambiyum) bulunmadığı için enine kalınlaşmayı sağlayacak doku eksiktir. İkincil büyüme gerçekleşemez."},{"t":"Sonucu çıkar","a":"Kalınlaşma az","d":"Bu nedenle çoğu tek çenekli bitki belirgin ikincil kalınlaşma göstermez. Gövdeleri genellikle ince kalır."}],"ans":"Düzenli kambiyum (yanal meristem) bulunmadığı için"},{"q":"Bir bitki dokusu kültüründe tek bir hücreden bütün bitkinin oluşturulabilmesini meristematik yetenekle açıklayınız.","steps":[{"t":"Hücreyi düşün","a":"Totipotent","d":"Bitki hücrelerinin çoğu uygun koşullarda yeniden bölünme yeteneği kazanabilir. Bu özelliğe totipotentlik denir."},{"t":"Meristematik dönüş","a":"Kallus oluşur","d":"Hücreler meristematik özellik kazanıp bölünerek kallus denen hücre kümesi oluşturur. Bu kümeden yeni dokular farklılaşabilir."},{"t":"Sonucu çıkar","a":"Tam bitki","d":"Kallustan kök, gövde ve yapraklar gelişerek tam bir bitki oluşur. Bu, hücrelerin meristematik yeteneğinin sonucudur."}],"ans":"Hücrelerin meristematik özellik kazanıp totipotentlikle bitki oluşturmasıyla"},{"q":"Kambiyumun içe ve dışa doğru farklı dokular üretmesini ve bunun gövde yapısına etkisini açıklayınız.","steps":[{"t":"İçe üretim","a":"Odun (ksilem)","d":"Kambiyum içe doğru bölünerek ksilem yani odun dokusu üretir. Odun su ve mineral iletimini ve desteği sağlar."},{"t":"Dışa üretim","a":"Soymuk (floem)","d":"Kambiyum dışa doğru ise floem yani soymuk dokusu üretir. Soymuk organik besin iletiminden sorumludur."},{"t":"Gövdeye etkisi","a":"Kalınlaşma","d":"İçte odunun birikmesi gövdenin büyük kısmını oluşturur ve gövde kalınlaşır. Böylece kambiyum gövde yapısını belirler."}],"ans":"İçe odun dışa soymuk üreterek gövdeyi kalınlaştırır"},{"q":"Bir ağaç kabuğunun halka şeklinde soyulması durumunda ağacın kuruma nedenini meristem ve iletim ilişkisiyle açıklayınız.","steps":[{"t":"Kabuğu düşün","a":"Floem ve kambiyum","d":"Ağaç kabuğunun iç kısmında floem (soymuk) ve kambiyum bulunur. Floem yapraklarda üretilen besini köke taşır."},{"t":"Soyulma etkisi","a":"Besin kesilir","d":"Halka şeklinde kabuk soyulunca floem kesilir ve köke besin gidemez. Ayrıca kambiyum da zarar görür."},{"t":"Sonucu yorumla","a":"Kök ölür, ağaç kurur","d":"Besinsiz kalan kök bir süre sonra ölür ve su alımı durur. Bu nedenle ağaç kurur; olaya halkalama denir."}],"ans":"Floem ve kambiyum kesilip köke besin gidemediği için ağaç kurur"},{"q":"Apikal meristemdeki hücre tabakalarının (tunika ve korpus) genel işlevini açıklayınız.","steps":[{"t":"Tunikayı düşün","a":"Dış tabakalar","d":"Apikal meristemde dışta yer alan ince hücre tabakalarına tunika denir. Bu tabakalar genellikle yüzeye dik bölünür."},{"t":"Korpusu düşün","a":"İç kütle","d":"Tunikanın altındaki iç hücre kütlesine korpus denir. Korpus çok yönlü bölünerek dokunun hacmini artırır."},{"t":"İşlevi birleştir","a":"Yüzey ve hacim","d":"Tunika yüzey alanının, korpus ise hacmin artmasını sağlar. Birlikte sürgün ucunun düzenli büyümesini sağlarlar."}],"ans":"Tunika yüzeyi, korpus hacmi büyütür; birlikte düzenli büyüme sağlar"},{"q":"İlkbaharda kambiyum etkinliğinin artmasıyla geniş hücreli odun oluşmasını fizyolojik nedenleriyle açıklayınız.","steps":[{"t":"İlkbahar koşulu","a":"Su ve sıcaklık bol","d":"İlkbaharda su ve uygun sıcaklık bol olduğu için bitki etkinliği artar. Kambiyum hızlı bölünür."},{"t":"Odun yapısı","a":"Geniş hücreler","d":"Hızlı su iletimi gerektiğinden geniş çaplı, ince çeperli odun hücreleri oluşur. Bu açık renkli ilkbahar odunudur."},{"t":"Sonucu yorumla","a":"Yaz odunuyla fark","d":"Yaz sonunda su azalınca dar, kalın çeperli koyu renk odun oluşur. İki tür odunun farkı yıllık halkayı meydana getirir."}],"ans":"Bol su nedeniyle kambiyum hızlı bölünüp geniş çaplı odun üretir"},{"q":"Meristem hücrelerinin organelce fakir görünmesinin (gelişmemiş plastit gibi) nedenini açıklayınız.","steps":[{"t":"Hücre durumunu düşün","a":"Farklılaşmamış","d":"Meristem hücreleri henüz belirli bir göreve özelleşmemiştir. Organeller görevle birlikte gelişir."},{"t":"Plastit durumu","a":"Proplastit","d":"Plastitler henüz olgunlaşmamış proplastit halindedir. Kloroplast gibi gelişmiş organeller yoktur."},{"t":"Nedeni özetle","a":"Görev bekler","d":"Hücre farklılaşınca görevine uygun organeller gelişir. Bu yüzden meristem hücreleri organelce fakir görünür."}],"ans":"Henüz farklılaşmadıkları için organelleri (plastit gibi) gelişmemiştir"},{"q":"Bir çelik (gövde parçası) ile bitki üretiminde meristem benzeri dokuların kök oluşturmasını açıklayınız.","steps":[{"t":"Çeliği düşün","a":"Gövde parçası","d":"Bir bitkiden alınan gövde parçasına çelik denir. Bu parça toprağa dikilir."},{"t":"Kök oluşumu","a":"Hücreler bölünür","d":"Kesilen bölgedeki hücreler meristematik özellik kazanıp bölünmeye başlar. Bu hücrelerden yeni kökler farklılaşır."},{"t":"Sonucu yorumla","a":"Yeni bitki","d":"Kök oluşan çelik bağımsız bir bitki haline gelir. Bu, hücrelerin yeniden meristematik etkinlik kazanmasıyla olur."}],"ans":"Çelikteki hücreler meristematik özellik kazanıp kök oluşturur"},{"q":"Birincil meristemin sürekli kendini yenilerken aynı zamanda farklılaşmış hücreler de üretebilmesini açıklayınız.","steps":[{"t":"Bölünmeyi düşün","a":"İki hücre","d":"Bir meristem hücresi bölündüğünde iki yavru hücre oluşur. Bu hücrelerin kaderi farklı olabilir."},{"t":"Hücre kaderi","a":"Biri kalır biri farklılaşır","d":"Yavru hücrelerden biri meristem olarak kalır, diğeri farklılaşarak doku oluşturur. Böylece meristem hem korunur hem doku üretir."},{"t":"Sonucu özetle","a":"Süreklilik","d":"Bu denge sayesinde meristem tükenmeden bitki sürekli büyür. Hem kendini yeniler hem yeni dokular üretir."}],"ans":"Bölünmede bir hücre meristem kalır, diğeri farklılaşır"},{"q":"Soğan kök ucu gibi bir örnekte meristem bölgesinin mikroskopta neden bol bölünen hücre içerdiğini açıklayınız.","steps":[{"t":"Kök ucunu düşün","a":"Büyüme bölgesi","d":"Soğan kök ucunda apikal meristem bulunur. Burası kökün boyca uzadığı bölgedir."},{"t":"Mikroskop görünümü","a":"Mitoz evreleri","d":"Bu bölgede hücreler sürekli mitoz geçirdiği için pek çok bölünme evresi görülür. Profaz, metafaz gibi evreler aynı anda gözlenir."},{"t":"Nedeni özetle","a":"Yoğun bölünme","d":"Meristemin sürekli bölünme özelliği nedeniyle bol bölünen hücre görülür. Bu yüzden mitoz incelemeleri kök ucunda yapılır."}],"ans":"Apikal meristemde sürekli mitoz olduğu için bölünen hücreler boldur"},{"q":"İkincil meristem etkinliğinin yaşlı ağaçlarda gövdenin merkezini cansız odunla doldurmasını açıklayınız.","steps":[{"t":"Kambiyumu hatırla","a":"İçe odun üretir","d":"Kambiyum her yıl içe doğru yeni odun (ksilem) üretir. Yeni odun dışta, eski odun içte kalır."},{"t":"Eski odun durumu","a":"Öz odun","d":"Merkezdeki eski odun zamanla iletim görevini bırakır ve cansızlaşır. Bu kısma öz odun denir ve destek sağlar."},{"t":"Sonucu yorumla","a":"Merkez cansızlaşır","d":"Yıllar boyunca biriken cansız öz odun gövdenin merkezini doldurur. Böylece yaşlı ağaçların ortası cansız odundan oluşur."}],"ans":"Kambiyumun ürettiği eski odunun cansızlaşıp öz odun oluşturmasıyla"},{"q":"Bir bitkide aşılama (aşı) işleminin tutmasında kambiyum dokularının rolünü açıklayınız.","steps":[{"t":"Aşıyı düşün","a":"İki parça birleşir","d":"Aşılamada anaç ile kalem adı verilen iki bitki parçası birbirine kaynaştırılır. Birleşme noktasının uyumu önemlidir."},{"t":"Kambiyum rolü","a":"Kambiyumlar buluşur","d":"İki parçanın kambiyum tabakaları karşılıklı getirilir ve bölünerek yeni hücreler üretir. Bu hücreler iki parçayı kaynaştırır."},{"t":"Sonucu yorumla","a":"Aşı tutar","d":"Kambiyumların ürettiği ortak doku iletim bağlantısını kurar ve aşı tutar. Kambiyum hizalanmazsa aşı tutmaz."}],"ans":"İki parçanın kambiyumları kaynaşıp ortak doku üreterek aşıyı tutturur"}]}},"parankima":{"ilkokul":{"kolay":[{"q":"Bitkilerde en çok bulunan, yumuşak ve dolgu görevi gören temel dokuya ne ad verilir?","steps":[{"t":"Doku miktarını düşün","a":"En yaygın doku","d":"Bitkinin yaprak, gövde ve kök gibi pek çok yerinde bulunan bir doku vardır. Bu doku bitkide en çok bulunan dokudur."},{"t":"Adını bul","a":"Parankima","d":"Bu yaygın temel dokuya parankima denir. Yumuşak ve dolgu görevi görür."}],"ans":"Parankima (temel) doku"},{"q":"Yaprakların yeşil renkli olması, içlerindeki hangi parankima türü sayesindedir?","steps":[{"t":"Yeşil rengi düşün","a":"Klorofil var","d":"Yaprakların yeşil olması içindeki klorofil sayesindedir. Klorofil fotosentez yapan hücrelerde bulunur."},{"t":"Türü bul","a":"Özümleme parankiması","d":"Klorofil taşıyan ve fotosentez yapan parankimaya özümleme parankiması denir. Yaprağı yeşil yapan budur."}],"ans":"Özümleme (fotosentez) parankiması"},{"q":"Patates yumrusunun nişasta deposu olması hangi parankima türü ile ilgilidir?","steps":[{"t":"Depoyu düşün","a":"Besin saklanır","d":"Patates içinde bol miktarda nişasta yani besin depolanır. Bu besin başka hücrelerde saklanır."},{"t":"Türü bul","a":"Depo parankiması","d":"Besin depolayan parankima türüne depo parankiması denir. Patatesteki nişasta burada saklanır."}],"ans":"Depo parankiması"},{"q":"Parankima hücreleri canlı mıdır yoksa cansız mı?","steps":[{"t":"Görevleri düşün","a":"Fotosentez, depo","d":"Parankima fotosentez yapar, besin depolar ve onarım sağlar. Bu görevler ancak canlı hücrelerle yapılabilir."},{"t":"Cevabı ver","a":"Canlı","d":"Bu görevleri yapabilmesi için parankima hücreleri canlıdır. İçlerinde sitoplazma ve çekirdek bulunur."}],"ans":"Canlı hücrelerdir"},{"q":"Su bitkilerinde yüzmeyi sağlayan, içinde hava boşlukları bulunan parankima türünün adı nedir?","steps":[{"t":"Hava boşluğunu düşün","a":"Hafif yapı","d":"Bazı su bitkilerinde içinde hava bulunan boşluklu hücreler vardır. Bu boşluklar bitkiyi hafifletir."},{"t":"Türü bul","a":"Havalandırma parankiması","d":"Hava boşlukları içeren bu parankimaya havalandırma parankiması denir. Bitkinin suda yüzmesine yardım eder."}],"ans":"Havalandırma parankiması"}],"zor":[{"q":"Parankima dokusu bitkide neden hem yaprakta hem kökte hem gövdede bulunur?","steps":[{"t":"Görevleri düşün","a":"Çok görevli","d":"Parankima fotosentez, depo, iletim ve havalandırma gibi pek çok görev yapar. Bu görevlere bitkinin her yerinde ihtiyaç vardır."},{"t":"Sonucu çıkar","a":"Her yerde","d":"Pek çok göreve sahip olduğu için parankima bitkinin her organında bulunur. Bu yüzden en yaygın dokudur."}],"ans":"Pek çok görevi olduğu için bitkinin her organında bulunur"},{"q":"Bir kavun veya karpuzun sulu ve etli kısmı hangi parankima türünden oluşur ve görevi nedir?","steps":[{"t":"Etli kısmı düşün","a":"Su ve besin saklar","d":"Kavun ve karpuzun etli kısmı bol su ve besin içerir. Bu maddeler hücrelerde depolanır."},{"t":"Türü bul","a":"Depo parankiması","d":"Su ve besin depolayan bu kısım depo parankimasıdır. Görevi besin ve su saklamaktır."}],"ans":"Depo parankiması; su ve besin depolar"},{"q":"Parankima hücreleri arasında boşluklar bulunması bitkiye nasıl bir yarar sağlar?","steps":[{"t":"Boşlukları düşün","a":"Hava dolar","d":"Parankima hücreleri arasında boşluklar bulunur ve bu boşluklara hava dolar. Hava içinde oksijen ve karbondioksit vardır."},{"t":"Yararı belirle","a":"Gaz alışverişi","d":"Bu hava boşlukları sayesinde hücrelere gaz alışverişi kolaylaşır. Fotosentez ve solunum için gerekli gazlar buradan sağlanır."}],"ans":"Hücreler arası boşluklar gaz alışverişini kolaylaştırır"},{"q":"Bir yaprak yırtıldığında zamanla iyileşmesinde parankimanın hangi özelliği rol oynar?","steps":[{"t":"İyileşmeyi düşün","a":"Yeni hücre gerek","d":"Yaprak yırtıldığında o bölgenin onarılması için yeni hücreler gerekir. Bu hücreleri üretebilen bir doku olmalıdır."},{"t":"Özelliği bul","a":"Bölünebilme","d":"Parankima hücreleri gerektiğinde bölünüp yeni hücreler üretebilir. Bu özellik sayesinde yaralı bölge onarılır."}],"ans":"Parankimanın bölünüp yara onarabilme özelliği"},{"q":"Özümleme parankimasının yaprağın üst kısmında yoğun bulunması neden faydalıdır?","steps":[{"t":"Işığı düşün","a":"Üstte ışık çok","d":"Yaprağın üst yüzeyi güneş ışığını en çok alan kısımdır. Fotosentez için ışık gereklidir."},{"t":"Yararı belirle","a":"Çok fotosentez","d":"Özümleme parankiması üstte yoğun olunca bol ışık alır ve çok fotosentez yapar. Böylece bitki daha çok besin üretir."}],"ans":"Üstte bol ışık aldığı için daha çok fotosentez yapar"}]},"ortaokul":{"kolay":[{"q":"Parankima dokusunun bitkideki en temel özelliği nedir?","steps":[{"t":"Yaygınlığı düşün","a":"En çok bulunan","d":"Parankima bitkide en yaygın bulunan temel dokudur. Pek çok organın dolgusunu oluşturur."},{"t":"Özelliği belirle","a":"Canlı ve çok görevli","d":"Parankima canlı hücrelerden oluşur ve birçok farklı görev yapar. Bu yüzden temel doku olarak adlandırılır."}],"ans":"Canlı, en yaygın ve çok görevli temel dokudur"},{"q":"Özümleme parankimasının görevi nedir?","steps":[{"t":"Klorofili hatırla","a":"Klorofil içerir","d":"Özümleme parankiması bol klorofil (kloroplast) içerir. Klorofil ışık enerjisini yakalar."},{"t":"Görevi belirle","a":"Fotosentez","d":"Bu doku klorofili sayesinde fotosentez yaparak besin üretir. Genellikle yapraklarda bulunur."}],"ans":"Fotosentez yaparak besin üretir"},{"q":"Depo parankimasının görevi nedir?","steps":[{"t":"Adını düşün","a":"Depolama","d":"Depo parankiması adından da anlaşılacağı gibi depolama görevi yapar. Pek çok organda bulunur."},{"t":"Neyi depolar","a":"Besin ve su","d":"Bu doku nişasta, şeker gibi besinleri ve suyu depolar. Patates ve havuç gibi yapılarda boldur."}],"ans":"Besin ve su depolar"},{"q":"Havalandırma parankimasının su bitkilerindeki görevi nedir?","steps":[{"t":"Hava boşluğunu düşün","a":"Geniş boşluklar","d":"Havalandırma parankimasında geniş hava boşlukları bulunur. Bu boşluklar hava ile dolar."},{"t":"Görevi belirle","a":"Yüzme ve gaz","d":"Hava boşlukları bitkiye yüzme kolaylığı sağlar ve gaz iletimini kolaylaştırır. Su bitkileri için çok önemlidir."}],"ans":"Yüzmeyi ve gaz alışverişini sağlar"},{"q":"Parankima hücrelerinin çeperi kalın mı yoksa ince midir?","steps":[{"t":"Görevini düşün","a":"Canlı, esnek","d":"Parankima canlı bir dokudur ve madde alışverişi yapar. Kalın çeper bunu zorlaştırırdı."},{"t":"Çeperi belirle","a":"İnce çeper","d":"Parankima hücreleri ince çeperlidir. Bu sayede madde alışverişi ve bölünme kolay olur."}],"ans":"İnce çeperlidir"}],"zor":[{"q":"Özümleme parankimasının iletim ve depo parankimasından farkı nedir?","steps":[{"t":"Özümlemeyi tanımla","a":"Klorofilli","d":"Özümleme parankiması bol klorofil içerir ve fotosentez yapar. Genellikle yapraklarda bulunur."},{"t":"Diğerlerini tanımla","a":"Klorofilsiz veya az","d":"İletim ve depo parankiması ise fotosentez yapmaz; iletim veya depolama görevi görür. Bunlarda klorofil ya yok ya çok azdır."},{"t":"Farkı özetle","a":"Görev farkı","d":"Özümleme fotosentez yaparken diğerleri iletim veya depolama yapar. Klorofil varlığı temel ayırt edici özelliktir."}],"ans":"Özümleme fotosentez yapar, diğerleri iletim veya depolama yapar"},{"q":"Çöl bitkilerinin etli ve sulu gövdelerinde hangi parankima türü gelişmiştir ve nedeni nedir?","steps":[{"t":"Çöl koşulunu düşün","a":"Su az","d":"Çölde su çok az bulunur ve bitkiler suyu biriktirmek zorundadır. Su depolayacak bir dokuya ihtiyaç vardır."},{"t":"Türü bul","a":"Su depo parankiması","d":"Çöl bitkilerinde su depolayan depo parankiması gelişmiştir. Etli gövde bol su saklar."},{"t":"Nedeni özetle","a":"Kuraklığa uyum","d":"Bu sayede bitki kurak dönemlerde depoladığı suyu kullanır. Depo parankiması kuraklığa uyum sağlar."}],"ans":"Su depolayan depo parankiması; kuraklığa uyum sağlar"},{"q":"Havalandırma parankimasının bataklık ve su bitkilerinde köklere oksijen taşımadaki rolünü açıklayınız.","steps":[{"t":"Ortam koşulunu düşün","a":"Köklerde oksijen az","d":"Bataklık ve su altındaki köklerde oksijen çok azdır. Kökler solunum için oksijene ihtiyaç duyar."},{"t":"Hava boşlukları","a":"Hava kanalı","d":"Havalandırma parankimasındaki hava boşlukları bir kanal gibi havayı köklere taşır. Üstteki yapraklardan oksijen aşağı iletilir."},{"t":"Sonucu belirle","a":"Kök solunumu","d":"Bu sayede su altındaki kökler oksijen alıp solunum yapabilir. Havalandırma parankiması yaşam için önemlidir."}],"ans":"Hava boşluklarıyla köklere oksijen taşıyıp solunumu sağlar"},{"q":"Bir yara sonrası parankimanın diğer dokulara dönüşebilmesi neden önemlidir?","steps":[{"t":"Yarayı düşün","a":"Doku kaybı","d":"Yaralanmada bitki belirli dokularını kaybeder. Bu dokuların yerine yenisi gerekir."},{"t":"Parankima rolü","a":"Farklılaşabilir","d":"Parankima bölünüp farklı dokulara dönüşebilir. Böylece kaybolan dokuların yerini doldurabilir."},{"t":"Önemini belirle","a":"Onarım sağlar","d":"Bu dönüşüm yeteneği sayesinde bitki yaralarını onarır ve yenilenir. Parankima bitkinin tamir dokusudur."}],"ans":"Farklı dokulara dönüşüp yara onarımını ve yenilenmeyi sağladığı için"},{"q":"Parankima hücrelerinin ince çeperli ve boşluklu olmasının madde alışverişine etkisini açıklayınız.","steps":[{"t":"İnce çeperi düşün","a":"Kolay geçiş","d":"İnce çeper madde ve suyun hücreye kolay girip çıkmasını sağlar. Kalın çeper bunu zorlaştırırdı."},{"t":"Boşlukları düşün","a":"Gaz dolaşır","d":"Hücreler arası boşluklara gaz dolar ve serbestçe dolaşır. Böylece oksijen ve karbondioksit hücrelere ulaşır."},{"t":"Etkisini özetle","a":"Hızlı alışveriş","d":"İnce çeper ve boşluklar birlikte madde ve gaz alışverişini kolaylaştırır. Parankima bu yapısıyla etkin çalışır."}],"ans":"İnce çeper ve boşluklar madde ile gaz alışverişini kolaylaştırır"}]},"lise":{"kolay":[{"q":"Parankima (temel) dokunun tanımını ve bitkideki yaygınlığını açıklayınız.","steps":[{"t":"Tanım","a":"Temel doku","d":"Parankima, canlı ve ince çeperli hücrelerden oluşan temel dokudur. Bitkinin pek çok organında dolgu görevi görür."},{"t":"Yaygınlık","a":"En çok bulunan","d":"Parankima bitkide en yaygın bulunan dokudur. Kök, gövde, yaprak ve meyvelerde bulunur."}],"ans":"Canlı, ince çeperli ve en yaygın temel dokudur"},{"q":"Özümleme parankimasının yapısını ve işlevini açıklayınız.","steps":[{"t":"Yapı","a":"Bol kloroplast","d":"Özümleme parankiması bol kloroplast (klorofil) içerir. Genellikle yaprakların mezofil tabakasında bulunur."},{"t":"İşlev","a":"Fotosentez","d":"Bu doku fotosentez yaparak organik besin üretir. Bitkinin temel besin kaynağıdır."}],"ans":"Bol kloroplastlıdır, fotosentez yapar"},{"q":"Depo parankimasının görevini ve örnek yapılarını açıklayınız.","steps":[{"t":"Görev","a":"Depolama","d":"Depo parankiması nişasta, şeker, yağ ve su gibi maddeleri depolar. Bitkinin besin ve su deposudur."},{"t":"Örnekler","a":"Patates, havuç","d":"Patates yumrusu, havuç kökü ve tohumların besi dokusu depo parankiması içerir. Bu yapılar yedek besin saklar."}],"ans":"Besin ve su depolar; patates, havuç gibi yapılarda bulunur"},{"q":"İletim parankimasının görevini açıklayınız.","steps":[{"t":"Konum","a":"İletim demeti yakını","d":"İletim parankiması iletim demetlerinin (ksilem ve floem) çevresinde bulunur. İletim dokularıyla iç içedir."},{"t":"Görev","a":"Madde aktarımı","d":"Bu doku iletim dokuları ile diğer hücreler arasında madde aktarımına yardım eder. Su ve besin geçişini kolaylaştırır."}],"ans":"İletim dokularıyla diğer hücreler arası madde aktarımına yardım eder"},{"q":"Havalandırma parankimasının yapısını ve işlevini açıklayınız.","steps":[{"t":"Yapı","a":"Geniş hava boşlukları","d":"Havalandırma parankimasında geniş hücreler arası hava boşlukları bulunur. Bu boşluklara aerankima da denir."},{"t":"İşlev","a":"Gaz iletimi ve yüzme","d":"Hava boşlukları gaz iletimini sağlar ve su bitkilerinde yüzmeye yardım eder. Köklere oksijen taşır."}],"ans":"Geniş hava boşlukları içerir, gaz iletimi ve yüzme sağlar"},{"q":"Parankima hücrelerinin yapısal özelliklerini (çeper, canlılık, koful) açıklayınız.","steps":[{"t":"Çeper ve canlılık","a":"İnce çeper, canlı","d":"Parankima hücreleri ince çeperli ve canlıdır. Bu özellikler madde alışverişini ve görev çeşitliliğini sağlar."},{"t":"Koful","a":"Belirgin koful","d":"Olgun parankima hücrelerinde belirgin bir koful bulunabilir. Hücreler arasında genellikle boşluklar vardır."}],"ans":"İnce çeperli, canlı, kofullu ve boşluklu hücrelerdir"},{"q":"Parankimanın yara onarımı ve yenilenmedeki rolünü açıklayınız.","steps":[{"t":"Bölünme yeteneği","a":"Yeniden bölünür","d":"Parankima hücreleri gerektiğinde yeniden bölünme yeteneği kazanabilir. Olgun hücreler meristematik özellik gösterebilir."},{"t":"Onarım","a":"Yara kapatır","d":"Bölünen parankima yaralı bölgeyi kapatır ve eksik dokuların yerini doldurur. Böylece bitki onarılır."}],"ans":"Yeniden bölünüp farklılaşarak yara onarımı ve yenilenmeyi sağlar"},{"q":"Parankimanın farklılaşma yeteneğinin bitki için önemini açıklayınız.","steps":[{"t":"Farklılaşmayı düşün","a":"Doku değişimi","d":"Parankima hücreleri gerektiğinde farklı dokulara dönüşebilir. Örneğin ikincil meristem parankimadan oluşabilir."},{"t":"Önem","a":"Esneklik","d":"Bu farklılaşma yeteneği bitkiye büyük bir esneklik kazandırır. Onarım, büyüme ve uyum sağlanır."}],"ans":"Farklılaşma yeteneği onarım, büyüme ve uyum esnekliği sağlar"},{"q":"Yaprakta palizat ve sünger parankiması arasındaki temel farkı açıklayınız.","steps":[{"t":"Palizat","a":"Sık, üstte","d":"Palizat parankiması yaprağın üst kısmında, uzun ve sık dizilmiş hücrelerden oluşur. Bol kloroplast içerir ve çok fotosentez yapar."},{"t":"Sünger","a":"Boşluklu, altta","d":"Sünger parankiması yaprağın altında, gevşek ve boşluklu hücrelerden oluşur. Gaz alışverişini kolaylaştırır."}],"ans":"Palizat sık ve fotosentezci, sünger boşluklu ve gaz alışverişlidir"},{"q":"Parankima hücrelerinin canlı olmasının görevleriyle ilişkisini açıklayınız.","steps":[{"t":"Görevleri düşün","a":"Aktif görevler","d":"Parankima fotosentez, depolama, iletim ve onarım gibi etkin görevler yapar. Bu görevler enerji ve metabolizma gerektirir."},{"t":"Canlılık ilişkisi","a":"Canlı olmalı","d":"Bu etkin görevler ancak canlı hücrelerle yapılabilir. Bu yüzden parankima hücreleri canlıdır."}],"ans":"Etkin görevleri ancak canlı hücreler yapabildiği için canlıdır"},{"q":"Tohumlardaki besi dokusunun (endosperm) parankima ile ilişkisini açıklayınız.","steps":[{"t":"Besi dokusunu düşün","a":"Besin deposu","d":"Tohumlarda embriyoyu besleyecek bol besin depolayan bir doku bulunur. Bu doku besi dokusu (endosperm) olarak adlandırılır."},{"t":"Parankima ilişkisi","a":"Depo parankiması","d":"Besi dokusu, besin depolayan parankima hücrelerinden oluşur. Yani bir tür depo parankimasıdır."}],"ans":"Besi dokusu besin depolayan bir tür depo parankimasıdır"},{"q":"Parankima dokusunun iletim dokularıyla birlikte bulunmasının işlevsel anlamını açıklayınız.","steps":[{"t":"Konumu düşün","a":"Demet çevresi","d":"İletim parankiması ksilem ve floem demetlerinin çevresinde yer alır. Bu konum madde alışverişi için uygundur."},{"t":"İşlevsel anlam","a":"Madde köprüsü","d":"Parankima iletim dokuları ile çevre hücreler arasında köprü görevi görür. Su ve besinin hücrelere dağıtımını kolaylaştırır."}],"ans":"İletim dokuları ile hücreler arası madde aktarımına köprü olur"},{"q":"Su bitkilerinde aerankima (havalandırma parankiması) gelişiminin uyumsal önemini açıklayınız.","steps":[{"t":"Su ortamını düşün","a":"Oksijen az","d":"Su ve bataklık ortamında çözünmüş oksijen azdır. Bitkinin batık kısımları oksijensiz kalabilir."},{"t":"Aerankima rolü","a":"Hava deposu","d":"Aerankima geniş hava boşluklarıyla oksijeni depolar ve iletir. Köklere ve batık dokulara oksijen sağlar."},{"t":"Uyumu özetle","a":"Su yaşamına uyum","d":"Bu yapı bitkinin su ortamında yaşamasını sağlayan bir uyumdur. Aerankima su bitkilerinde belirgin gelişir."}],"ans":"Hava boşluklarıyla oksijen sağlayarak su yaşamına uyum getirir"},{"q":"Çöl bitkilerinde (sukkulent) su depo parankimasının gelişmesinin nedenini açıklayınız.","steps":[{"t":"Çöl koşulu","a":"Kuraklık","d":"Çölde su nadiren ve kısa süre bulunur. Bitki suyu uzun süre saklamak zorundadır."},{"t":"Parankima gelişimi","a":"Su deposu","d":"Sukkulent bitkilerin etli gövde ve yapraklarında su depo parankiması gelişir. Bu doku bol su saklar."},{"t":"Nedeni özetle","a":"Kuraklık uyumu","d":"Bu sayede bitki kurak dönemlerde depoladığı suyu kullanır. Su depo parankiması kuraklığa uyumdur."}],"ans":"Kuraklığa uyum için su depolamak amacıyla gelişir"},{"q":"Parankima dokusunun bitkide birden çok görevi yerine getirebilmesinin nedenini açıklayınız.","steps":[{"t":"Hücre özelliğini düşün","a":"Az özelleşmiş","d":"Parankima hücreleri fazla özelleşmemiş, basit yapılı canlı hücrelerdir. Bu yapı esneklik sağlar."},{"t":"Görev çeşitliliği","a":"Çok yönlü","d":"Az özelleşmiş olmaları sayesinde fotosentez, depo, iletim ve havalandırma gibi farklı görevleri yapabilirler. İçerdikleri organele göre görev değişir."}],"ans":"Az özelleşmiş esnek yapısı birden çok görev yapmasını sağlar"}],"zor":[{"q":"Bir yaprağın mezofil tabakasında palizat ve sünger parankimasının iş bölümünü fotosentez verimi açısından açıklayınız.","steps":[{"t":"Palizatı düşün","a":"Işık yakalar","d":"Üstte yer alan palizat parankiması sık dizilmiş ve bol kloroplastlıdır. Gelen ışığı en üst düzeyde yakalayıp yoğun fotosentez yapar."},{"t":"Süngeri düşün","a":"Gaz sağlar","d":"Altta yer alan sünger parankiması boşlukludur ve karbondioksit ile oksijenin dolaşmasını sağlar. Stomalardan gelen gazları hücrelere iletir."},{"t":"İş bölümünü özetle","a":"Verim artar","d":"Palizat ışık ve fotosentezi, sünger gaz akışını üstlenir. Bu iş bölümü fotosentez verimini en üst düzeye çıkarır."}],"ans":"Palizat ışık ve fotosentezi, sünger gaz akışını üstlenip verimi artırır"},{"q":"Olgun bir parankima hücresinin yaralanma sonrası yeniden bölünme kazanmasını hücre düzeyinde açıklayınız.","steps":[{"t":"Olgun hücreyi düşün","a":"Farklılaşmış","d":"Olgun parankima hücresi belirli bir göreve farklılaşmıştır ancak çekirdeği ve genetik bilgisi tamdır. Bölünme yeteneğini tamamen kaybetmemiştir."},{"t":"Yaralanma uyarısı","a":"Sinyal alır","d":"Yaralanma sonrası hücre hormonal ve kimyasal sinyaller alır. Bu sinyaller hücre döngüsünü yeniden başlatır."},{"t":"Sonucu özetle","a":"Meristematik olur","d":"Hücre meristematik özellik kazanıp bölünmeye başlar ve yarayı onarır. Bu durum parankimanın totipotent yapısının sonucudur."}],"ans":"Sinyallerle hücre döngüsünü yeniden başlatıp meristematik özellik kazanır"},{"q":"Nilüfer gibi su bitkilerinin yaprak ve gövdelerinin suda dik durmasında havalandırma parankimasının rolünü açıklayınız.","steps":[{"t":"Hava boşluklarını düşün","a":"Hava dolu","d":"Havalandırma parankimasındaki geniş boşluklar hava ile doludur. Hava sudan hafif olduğu için kaldırma kuvveti sağlar."},{"t":"Yüzdürme etkisi","a":"Destek sağlar","d":"Hava boşlukları bitkiye kaldırma kuvveti vererek su içinde dik durmasına yardım eder. Bitki bu sayede yüzeye yakın kalır."},{"t":"Sonucu özetle","a":"Dik durur","d":"Bu kaldırma etkisiyle yaprak ve gövdeler suda dik kalabilir. Havalandırma parankiması destek ve yüzme sağlar."}],"ans":"Hava boşluklarının kaldırma kuvvetiyle bitki suda dik durur"},{"q":"Parankimanın ikincil meristem (kambiyum) oluşumundaki kaynak rolünü açıklayınız.","steps":[{"t":"Kambiyumun kökeni","a":"Sonradan oluşur","d":"İkincil meristem olan kambiyum embriyonik değildir, sonradan oluşur. Bunun için bölünebilen hücreler gerekir."},{"t":"Parankima rolü","a":"Yeniden bölünür","d":"Olgun parankima hücreleri yeniden bölünme yeteneği kazanıp kambiyumu oluşturur. Yani kambiyum parankimadan köken alır."},{"t":"Sonucu özetle","a":"İkincil büyüme","d":"Parankimadan oluşan kambiyum enine kalınlaşmayı sağlar. Böylece parankima ikincil büyümenin kaynağıdır."}],"ans":"Olgun parankima yeniden bölünüp kambiyumu (ikincil meristem) oluşturur"},{"q":"Patates yumrusunun karanlıkta filiz vermesinde depo parankimasının rolünü açıklayınız.","steps":[{"t":"Depo parankimasını düşün","a":"Nişasta deposu","d":"Patates yumrusu depo parankimasında bol nişasta saklar. Bu nişasta yedek besindir."},{"t":"Filizlenme","a":"Besin kullanılır","d":"Filizlenirken gözlerdeki tomurcuklar depodaki nişastayı şekere çevirip kullanır. Bu besin filizin büyümesini sağlar."},{"t":"Sonucu özetle","a":"Karanlıkta büyür","d":"Işık olmasa bile depolanan besinle filiz büyüyebilir. Depo parankiması bu enerjiyi sağlar."}],"ans":"Depo parankimasındaki nişasta besin olarak kullanılıp filizi besler"},{"q":"Bir bitkinin gövdesinde parankima hücrelerinin turgor basıncıyla destek sağlamasını açıklayınız.","steps":[{"t":"Turgoru düşün","a":"Su ile şişme","d":"Parankima hücreleri su alınca kofulları şişer ve hücre içi basınç (turgor) artar. Hücre çeperine doğru basınç oluşur."},{"t":"Destek etkisi","a":"Dik durur","d":"Şişen hücreler birbirine yaslanarak dokuyu sertleştirir ve otsu gövdenin dik durmasını sağlar. Bu bir tür hidrostatik destektir."},{"t":"Su azalınca","a":"Solar","d":"Su azalınca turgor düşer, hücreler büzülür ve bitki solar. Bu da turgorun destekteki önemini gösterir."}],"ans":"Turgor basıncıyla şişen hücreler otsu gövdeye destek sağlar"},{"q":"Meyve olgunlaşırken parankima hücrelerindeki değişimleri (nişastanın şekere dönüşmesi gibi) açıklayınız.","steps":[{"t":"Olgunlaşmamış meyve","a":"Nişasta bol","d":"Olgunlaşmamış meyvenin parankimasında bol nişasta bulunur. Bu yüzden tatları genellikle ham ve nişastalıdır."},{"t":"Olgunlaşma","a":"Şekere dönüşür","d":"Olgunlaşırken enzimler nişastayı şekere dönüştürür. Parankima hücreleri tatlanır ve yumuşar."},{"t":"Sonucu özetle","a":"Tatlanır","d":"Bu dönüşümle meyve tatlanır ve yenebilir hale gelir. Depo parankimasındaki bu değişim olgunlaşmanın temelidir."}],"ans":"Parankimadaki nişasta enzimlerle şekere dönüşüp meyve tatlanır"},{"q":"Parankima hücrelerinin hücreler arası boşluklarının kökte oksijen iletimini nasıl kolaylaştırdığını açıklayınız.","steps":[{"t":"Kök solunumunu düşün","a":"Oksijen gerek","d":"Kök hücreleri canlı kalmak için solunum yapar ve oksijene ihtiyaç duyar. Toprak altında oksijen sınırlı olabilir."},{"t":"Boşlukların rolü","a":"Hava kanalı","d":"Parankima hücreleri arasındaki boşluklar birbirine bağlanarak hava kanalları oluşturur. Üstten gelen oksijen bu kanallarla köke iner."},{"t":"Sonucu özetle","a":"Solunum sürer","d":"Bu kanallar sayesinde kök hücreleri oksijen alıp solunum yapar. Hücreler arası boşluklar oksijen iletimini kolaylaştırır."}],"ans":"Hücreler arası boşluklar hava kanalı oluşturup köke oksijen iletir"},{"q":"Soğanın etli yaprakları (depo yaprakları) ile parankimanın depolama görevi arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Soğanı düşün","a":"Etli yapraklar","d":"Soğan, üst üste binmiş etli yapraklardan oluşur. Bu yapraklar kalın ve sulu görünür."},{"t":"Parankima ilişkisi","a":"Depo parankiması","d":"Etli yapraklar bol depo parankiması içerir ve burada şeker ve su depolanır. Soğan bir yer altı depo organıdır."},{"t":"Sonucu özetle","a":"Yedek besin","d":"Depolanan besin bitkinin yeniden büyümesi için kullanılır. Bu, parankimanın depolama görevinin örneğidir."}],"ans":"Etli yapraklardaki depo parankiması şeker ve su depolar"},{"q":"Klorofilsiz depo parankimasının (örneğin kökteki) fotosentez yapamamasının nedenini açıklayınız.","steps":[{"t":"Kloroplastı düşün","a":"Klorofil gerek","d":"Fotosentez kloroplast içindeki klorofil ile yapılır. Klorofil ışık enerjisini kimyasal enerjiye çevirir."},{"t":"Depo parankiması","a":"Klorofil yok","d":"Kök gibi karanlık ortamlardaki depo parankimasında klorofil bulunmaz. Plastitler renksiz lökoplast halindedir."},{"t":"Sonucu özetle","a":"Fotosentez yok","d":"Klorofil olmadığı için bu hücreler fotosentez yapamaz, yalnızca depolama yapar. Renksiz plastitler nişasta depolar."}],"ans":"Klorofil (kloroplast) bulunmadığı için fotosentez yapamaz"},{"q":"Bir bitki dokusu kültüründe parankima hücrelerinden kallus oluşumunu açıklayınız.","steps":[{"t":"Hücreyi düşün","a":"Totipotent parankima","d":"Parankima hücreleri totipotent yani tüm bitkiyi oluşturma potansiyeline sahiptir. Uygun koşulda yeniden bölünebilir."},{"t":"Kallus oluşumu","a":"Düzensiz çoğalma","d":"Besin ortamında ve hormon etkisiyle parankima hücreleri düzensizce bölünüp kallus denen hücre kümesi oluşturur. Bu kümede farklılaşma henüz olmamıştır."},{"t":"Sonucu özetle","a":"Yeni bitki temeli","d":"Kallustan uygun hormonlarla kök ve sürgün geliştirilerek yeni bitki elde edilir. Parankima bu sürecin başlangıç kaynağıdır."}],"ans":"Parankima hücreleri hormonlarla bölünüp kallus oluşturur"},{"q":"Sukkulent (etli) bitkilerde su depo parankimasının kuraklık döneminde su kaybını azaltmadaki rolünü açıklayınız.","steps":[{"t":"Su deposunu düşün","a":"Bol su saklar","d":"Sukkulent bitkilerin etli dokularındaki su depo parankiması bol su saklar. Bu su gövde ve yapraklarda biriktirilir."},{"t":"Kuraklık dönemi","a":"Yavaş kullanım","d":"Kuraklıkta bitki bu suyu yavaş yavaş kullanır ve dışarıdan suya bağımlılığı azalır. Hücreler turgorunu korur."},{"t":"Sonucu özetle","a":"Hayatta kalma","d":"Depolanan su sayesinde bitki uzun kurak dönemleri atlatır. Su depo parankiması çöl yaşamına uyum sağlar."}],"ans":"Depoladığı suyu yavaş kullanarak bitkinin kuraklığı atlatmasını sağlar"},{"q":"Yaprak dökmeyen bitkilerde gövde parankimasının kışın canlı kalıp besin saklamasını açıklayınız.","steps":[{"t":"Kış koşulunu düşün","a":"Fotosentez azalır","d":"Kışın soğuk ve az ışık nedeniyle fotosentez azalır. Bitki dışarıdan az besin üretebilir."},{"t":"Parankima rolü","a":"Yedek besin","d":"Gövde ve kök parankiması yaz boyunca depoladığı besini kışın kullanır. Bu canlı hücreler yedek besin sağlar."},{"t":"Sonucu özetle","a":"Hayatta kalma","d":"Depolanan besin bitkinin kışı atlatmasını ve ilkbaharda yeniden büyümesini sağlar. Parankima bu açıdan hayati önemdedir."}],"ans":"Canlı parankima depoladığı besinle bitkinin kışı atlatmasını sağlar"},{"q":"Bir bitki gövdesinde parankima, kollenkima ve sklerenkimanın destek açısından farkını açıklayınız.","steps":[{"t":"Parankimayı düşün","a":"Turgorla destek","d":"Parankima ince çeperlidir ve yalnızca turgor basıncıyla geçici destek sağlar. Su kaybında bu destek zayıflar."},{"t":"Kollenkima","a":"Esnek destek","d":"Kollenkima köşeleri kalınlaşmış canlı hücrelerden oluşur ve genç organlara esnek destek verir. Büyüyen kısımlarda boldur."},{"t":"Sklerenkima","a":"Sert destek","d":"Sklerenkima kalın ve odunlaşmış çeperli cansız hücrelerden oluşup kalıcı ve sert destek sağlar. Olgun kısımlarda bulunur."}],"ans":"Parankima turgorla, kollenkima esnek, sklerenkima sert ve kalıcı destek verir"},{"q":"Parankima hücrelerindeki kloroplast, lökoplast ve kromoplast bulunmasının görev farklılığını açıklayınız.","steps":[{"t":"Kloroplast","a":"Fotosentez","d":"Kloroplast içeren parankima yeşildir ve fotosentez yapar. Özümleme parankimasında bulunur."},{"t":"Lökoplast","a":"Depolama","d":"Lökoplast renksizdir ve nişasta gibi besinleri depolar. Kök ve yumru gibi karanlık dokularda bulunur."},{"t":"Kromoplast","a":"Renk verir","d":"Kromoplast sarı, turuncu, kırmızı renk pigmentleri içerir ve meyve ile çiçeklere renk verir. Bu renk tozlaşma ve tohum yayılmasını kolaylaştırır."}],"ans":"Plastit türüne göre parankima fotosentez, depolama veya renklendirme yapar"}]}},"kollenkima":{"ilkokul":{"kolay":[{"q":"Bir bitkinin genç gövdesini elimizle bükmeye çalıştığımızda kırılmadan eğildiğini görüyoruz. Bu esnekliği sağlayan canlı destek dokusu hangisidir? Adım adım bulalım.","steps":[{"t":"Genç gövdenin özelliği","a":"Genç gövde esnektir","d":"Genç bitki gövdeleri kolayca eğilir ama hemen kırılmaz. Bu özellik, içlerinde esnek destek hücrelerinin bulunmasından kaynaklanır."},{"t":"Doku hücreleri canlıdır","a":"Köşeleri kalın canlı hücreler","d":"Bu dokuyu oluşturan hücreler canlıdır ve köşeleri kalınlaşmıştır. Hem destek verir hem de bitkinin büyümesine engel olmaz."}],"ans":"Kollenkima (pek doku)"},{"q":"Bir yaprağın sapını parmaklarımızla yokladığımızda dayanıklı ama esnek olduğunu hissediyoruz. Bu esnek desteği veren doku hangisidir? Birlikte bulalım.","steps":[{"t":"Yaprak sapının yapısı","a":"Yaprak sapı esnektir","d":"Yaprak sapları rüzgârda sallanır ama kolay kolay kopmaz. İçlerinde esnek bir destek dokusu bulunur."},{"t":"Esnek dokunun adı","a":"Köşeleri kalınlaşmış doku","d":"Bu destek dokusunun hücreleri köşelerinden kalınlaşmıştır. Canlı oldukları için bitkiye hem destek hem esneklik verirler."}],"ans":"Kollenkima"},{"q":"Kereviz sapını ısırdığımızda içinden ipliksi, dayanıklı teller çıkar. Sapın esnek ve dik durmasını sağlayan bu canlı destek dokusu hangisidir? Adım adım düşünelim.","steps":[{"t":"Kereviz sapının dayanıklılığı","a":"Sap dik durur","d":"Kereviz sapı uzun olmasına rağmen dik durabilir. Bunu sağlayan, sapın içindeki destek dokusudur."},{"t":"Dokunun esnekliği","a":"Esnek ve canlı","d":"Bu doku hem destek verir hem de esnektir, çünkü hücreleri canlıdır. Köşeleri kalınlaşmış olan bu doku kollenkimadır."}],"ans":"Kollenkima"},{"q":"Bir bitki büyürken hem desteğe hem de uzayabilme esnekliğine ihtiyaç duyar. Büyümeye devam eden organlara esneklikle destek veren canlı doku hangisidir? Bulalım.","steps":[{"t":"Büyüyen organın ihtiyacı","a":"Hem destek hem esneklik","d":"Büyüyen bir bitki organının desteğe ihtiyacı vardır ama sert bir doku büyümesini durdurur. Bu yüzden esnek bir destek gerekir."},{"t":"Uygun doku","a":"Canlı, esnek destek","d":"Kollenkima hücreleri canlı ve esnek olduğu için büyümeyi engellemeden destek verir. Genç ve büyüyen organlarda bulunur."}],"ans":"Kollenkima"},{"q":"Domates bitkisinin yeni çıkan yeşil gövdesi yumuşak ama dik durur. Bu genç gövdeye esnek destek sağlayan dokunun adı nedir? Adım adım bulalım.","steps":[{"t":"Genç gövdenin görünümü","a":"Yeşil ve yumuşak","d":"Domatesin yeni gövdesi yeşil ve yumuşaktır ama yine de dik durur. İçindeki destek dokusu bunu sağlar."},{"t":"Destek dokusunun türü","a":"Köşeleri kalın canlı doku","d":"Genç gövdelerde bulunan bu doku canlıdır ve köşeleri kalınlaşmıştır. Bu doku kollenkimadır."}],"ans":"Kollenkima"}],"zor":[{"q":"Bir öğrenci genç bir gövdenin destek dokusunu mikroskopta inceliyor ve hücrelerin canlı olduğunu, köşelerinin kalınlaştığını görüyor. Bu hücreler hangi dokuya aittir ve neden büyümeyi engellemez? Adım adım çözelim.","steps":[{"t":"Hücrelerin canlı olması","a":"Canlı hücreler","d":"Mikroskopta hücrelerin içinde sitoplazma görülmesi, hücrelerin canlı olduğunu gösterir. Bu önemli bir ipucudur."},{"t":"Köşelerin kalınlaşması","a":"Köşe kalınlaşması","d":"Hücre köşelerinin kalınlaşması kollenkimanın en belirgin özelliğidir. Bu kalınlaşma selülozdan oluşur."},{"t":"Büyümeye engel olmaması","a":"Esnek olduğu için","d":"Kollenkima hücreleri canlı ve esnek olduğundan organ uzarken birlikte uzayabilir. Bu yüzden büyümeyi durdurmaz."}],"ans":"Kollenkima (canlı ve esnek olduğu için)"},{"q":"Bir bahçıvan rüzgârlı havada genç fidanların gövdelerinin kırılmadan eğilip tekrar dikleştiğini gözlemliyor. Bu esnek davranışı sağlayan doku hangisidir ve hücreleri ne tür bir maddeyle kalınlaşmıştır? Çözelim.","steps":[{"t":"Eğilip dikleşme","a":"Esnek destek","d":"Gövdenin rüzgârda eğilip kırılmaması, esnek bir destek dokusunun varlığını gösterir. Sert bir doku olsaydı kırılırdı."},{"t":"Dokunun belirlenmesi","a":"Kollenkima","d":"Bu esnek davranışı sağlayan doku kollenkimadır. Genç gövdelerde bulunur ve canlı hücrelerden oluşur."},{"t":"Kalınlaşma maddesi","a":"Selüloz","d":"Kollenkima hücrelerinin köşeleri selülozca zengin bir kalınlaşma içerir. Selüloz esnek olduğu için doku da esnek kalır."}],"ans":"Kollenkima (selülozla kalınlaşmış)"},{"q":"İki destek dokusundan biri canlı ve esnek, diğeri ölü ve serttir. Genç, büyümeye devam eden bir yaprak sapında hangi dokuyu bulmayı bekleriz ve neden? Adım adım açıklayalım.","steps":[{"t":"İki dokunun karşılaştırılması","a":"Canlı/esnek ve ölü/sert","d":"Bitkilerde iki temel destek dokusu vardır. Biri canlı ve esnek olan kollenkima, diğeri ölü ve sert olan sklerenkimadır."},{"t":"Genç organın gereksinimi","a":"Esnek destek gerekir","d":"Büyümeye devam eden bir organ uzamaya devam ettiği için esnek desteğe ihtiyaç duyar. Sert bir doku bu büyümeyi engellerdi."},{"t":"Uygun dokunun seçimi","a":"Kollenkima","d":"Genç ve büyüyen yaprak saplarında kollenkima bulunur. Çünkü esnek olduğu için organ büyürken birlikte uzayabilir."}],"ans":"Kollenkima"},{"q":"Bir bitki dersinde öğretmen, kereviz sapındaki ipliksi yapıların canlı olduğunu söylüyor. Bu yapı hangi destek dokusudur ve neden olgun bitkilerde de canlılığını koruyabilir? Çözelim.","steps":[{"t":"İpliksi yapının canlılığı","a":"Canlı destek dokusu","d":"Kereviz sapındaki ipliksi destek yapılarının canlı olması önemli bir ipucudur. Çünkü tüm destek dokuları canlı değildir."},{"t":"Dokunun adı","a":"Kollenkima","d":"Canlı kalan destek dokusu kollenkimadır. Hücreleri olgunlukta bile canlılığını korur."},{"t":"Canlı kalmasının nedeni","a":"Çeperi tam ligninleşmez","d":"Kollenkima çeperleri sadece selülozla kalınlaştığı, tamamen ligninleşmediği için hücreler canlı kalabilir. Bu da esneklik sağlar."}],"ans":"Kollenkima"},{"q":"Bir öğrenci aynı bitkinin genç bölgesinde esnek, olgun bölgesinde sert destek dokuları buluyor. Genç bölgedeki esnek doku hangisidir ve hangi organlarda yoğun olarak görülür? Adım adım bulalım.","steps":[{"t":"Genç bölgenin dokusu","a":"Esnek destek","d":"Bitkinin genç bölgelerinde esnek bir destek dokusu bulunur. Bu doku, organ büyürken esneklik sağlar."},{"t":"Dokunun adlandırılması","a":"Kollenkima","d":"Bu esnek doku kollenkimadır. Canlı hücrelerden oluşur ve köşeleri selülozla kalınlaşmıştır."},{"t":"Bulunduğu organlar","a":"Genç gövde ve yaprak sapı","d":"Kollenkima genç gövdelerde, yaprak saplarında ve yaprak damarlarında yoğun olarak bulunur. Bu organlar hâlâ büyümektedir."}],"ans":"Kollenkima"}]},"ortaokul":{"kolay":[{"q":"Bitkilerde destek görevi gören dokulardan biri canlı hücrelerden oluşur ve köşeleri kalınlaşmıştır. Bu dokunun adı nedir ve nerede bulunur? Adım adım belirleyelim.","steps":[{"t":"Hücre özelliği","a":"Canlı, köşe kalınlaşmalı","d":"Bu destek dokusunun hücreleri canlıdır ve özellikle köşelerinden kalınlaşmıştır. Bu köşe kalınlaşması dokuya esneklik verir."},{"t":"Bulunduğu yer","a":"Genç organlarda","d":"Bu doku genç gövdelerde ve yaprak saplarında bulunur. Büyümeye devam eden organlara esnek destek sağlar."}],"ans":"Kollenkima"},{"q":"Kollenkima dokusunun büyümeye devam eden organlara nasıl destek sağladığını ve sklerenkimadan farkını adım adım açıklayalım.","steps":[{"t":"Kollenkimanın esnekliği","a":"Esnek destek","d":"Kollenkima canlı hücrelerden oluştuğu için esnektir. Organ uzarken birlikte uzayabilir, böylece büyümeyi engellemez."},{"t":"Sklerenkimadan farkı","a":"Canlı ve esnek olması","d":"Sklerenkima ölü ve sert hücrelerden oluşurken kollenkima canlı ve esnektir. Bu yüzden kollenkima genç organlarda, sklerenkima olgun organlarda bulunur."}],"ans":"Kollenkima esnek destek verir, sklerenkima sert destek verir"},{"q":"Kollenkima hücrelerinin köşelerindeki kalınlaşma hangi maddeden oluşur ve bu maddenin esneklik sağlamasının nedeni nedir? Adım adım çözelim.","steps":[{"t":"Kalınlaşmanın maddesi","a":"Selüloz","d":"Kollenkima hücrelerinin köşe kalınlaşması selülozca zengindir. Selüloz, hücre çeperinin temel yapı maddesidir."},{"t":"Esneklik nedeni","a":"Selüloz esnektir","d":"Selüloz lignine göre daha esnek bir maddedir. Bu yüzden selülozla kalınlaşmış kollenkima esnekliğini korur."}],"ans":"Selüloz (esnek bir madde olduğu için)"},{"q":"Bir bitkide yaprak damarlarının altında çoğunlukla kollenkima bulunur. Bu dokunun yaprağa ne tür bir katkı sağladığını adım adım açıklayalım.","steps":[{"t":"Yaprak damarının görevi","a":"Yaprağı destekler","d":"Yaprak damarları yaprağın açık ve düz durmasını sağlar. Bunun için destek dokusuna ihtiyaç vardır."},{"t":"Kollenkimanın katkısı","a":"Esnek destek","d":"Damar altındaki kollenkima yaprağa esnek destek verir. Bu sayede yaprak rüzgârda kıvrılsa bile kolayca kırılmaz."}],"ans":"Yaprağa esnek destek sağlar"},{"q":"Kollenkimanın olgun bir bitkide neden ana destek dokusu olmadığını ve hangi organlarda baskın olduğunu adım adım açıklayalım.","steps":[{"t":"Kollenkimanın sınırı","a":"Sadece esnek destek","d":"Kollenkima esnek destek verir ama çok ağır yükleri taşıyacak kadar sert değildir. Bu yüzden büyük ve olgun yapıların tek desteği olamaz."},{"t":"Baskın olduğu organlar","a":"Genç organlar","d":"Kollenkima genç gövdelerde, yaprak saplarında ve damarlarda baskındır. Bu organlar hâlâ büyüdüğü için esnek desteğe ihtiyaç duyar."}],"ans":"Genç organlarda baskındır; olgun organlarda sklerenkima desteği devralır"}],"zor":[{"q":"Bir öğrenci enine kesit aldığı genç bir gövdede, epidermisin hemen altında köşeleri kalınlaşmış canlı hücreler buluyor. Bu doku nedir, hangi maddeyle kalınlaşmıştır ve görevi nedir? Adım adım çözelim.","steps":[{"t":"Konum ve görünüm","a":"Epidermis altında köşe kalınlaşmalı","d":"Genç gövdede epidermisin hemen altında, köşeleri kalınlaşmış hücreler kollenkimanın tipik konumudur. Bu konum dış desteğe yardımcı olur."},{"t":"Hücrelerin canlılığı","a":"Canlı hücreler","d":"Hücrelerin canlı olması bu dokunun kollenkima olduğunu doğrular. Sklerenkima hücreleri olgunlukta ölüdür."},{"t":"Kalınlaşma ve görev","a":"Selüloz, esnek destek","d":"Köşeler selülozla kalınlaşmıştır ve doku esnek destek sağlar. Genç organ büyürken birlikte uzayabildiği için büyümeyi engellemez."}],"ans":"Kollenkima (selülozla kalınlaşmış, esnek destek sağlar)"},{"q":"Bir bitki büyürken genç gövdesi hem destek hem esnekliğe ihtiyaç duyar; olgunlaştığında ise daha sert desteğe geçer. Bu geçişi adım adım açıklayarak hangi dokuların rol aldığını belirleyelim.","steps":[{"t":"Genç dönem desteği","a":"Kollenkima","d":"Genç gövdede büyüme devam ettiği için esnek destek gerekir. Bu görevi canlı ve esnek olan kollenkima üstlenir."},{"t":"Olgun dönem desteği","a":"Sklerenkima/odun","d":"Organ olgunlaşıp büyümesi durunca daha sert desteğe ihtiyaç duyar. Bu görevi ligninle sertleşmiş sklerenkima ve odun dokusu üstlenir."},{"t":"Geçişin nedeni","a":"Büyümenin durması","d":"Esnek destekten sert desteğe geçiş, büyümenin durmasıyla ilgilidir. Büyüme bitince esnekliğe gerek kalmaz, dayanıklılık öne çıkar."}],"ans":"Genç dönemde kollenkima, olgun dönemde sklerenkima"},{"q":"Kollenkima hücreleri köşe, çeper boyunca ve boşluk kenarlarında farklı şekillerde kalınlaşabilir. Bu kalınlaşma türlerinin ortak yönünü ve dokunun temel işlevini adım adım açıklayalım.","steps":[{"t":"Kalınlaşma çeşitliliği","a":"Farklı bölgelerde kalınlaşma","d":"Kollenkimada kalınlaşma genelde köşelerde görülür ama çeper boyunca da olabilir. Her durumda kalınlaşma düzensiz dağılır."},{"t":"Ortak madde","a":"Selüloz","d":"Tüm kalınlaşma türlerinde temel madde selülozdur. Selüloz esnek olduğu için hücre canlı ve esnek kalır."},{"t":"Temel işlev","a":"Esnek destek","d":"Kalınlaşma nerede olursa olsun dokunun görevi esnek destektir. Bu özellik büyümeye devam eden organlar için idealdir."}],"ans":"Hepsi selülozla kalınlaşır ve esnek destek sağlar"},{"q":"Bir araştırmacı, sürekli rüzgâra maruz kalan bitkilerin gövdelerinde kollenkima miktarının arttığını gözlemliyor. Bu durumu kollenkimanın işleviyle ilişkilendirerek adım adım açıklayalım.","steps":[{"t":"Rüzgârın etkisi","a":"Mekanik zorlanma","d":"Rüzgâr bitki gövdesini sürekli eğilmeye zorlar. Bu mekanik zorlanma, gövdenin esnek desteğe daha fazla ihtiyaç duymasına yol açar."},{"t":"Kollenkimanın rolü","a":"Esnek destek artar","d":"Gövde, rüzgâra dayanmak için daha fazla esnek destek dokusu üretir. Bu doku kollenkimadır ve eğilmeye karşı direnç sağlar."},{"t":"Sonuç","a":"Adaptasyon","d":"Bitki, mekanik zorlanmaya kollenkima miktarını artırarak uyum sağlar. Böylece kırılmadan eğilebilir hâle gelir."}],"ans":"Kollenkima esnek destek verdiği için rüzgâr zorlanmasıyla miktarı artar"},{"q":"Genç bir kereviz sapının enine kesitinde, dış kenara yakın bölgede köşeleri belirgin biçimde kalınlaşmış canlı hücre kümeleri görülüyor. Bu dokuyu tanımlayarak konum ve işlev ilişkisini adım adım açıklayalım.","steps":[{"t":"Dokunun tanınması","a":"Köşe kalınlaşmalı canlı doku","d":"Köşeleri belirgin kalınlaşmış canlı hücreler kollenkimaya işaret eder. Bu, kerevizin ipliksi destek dokusudur."},{"t":"Konumun anlamı","a":"Dış kenara yakın","d":"Kollenkimanın dış kenara yakın bulunması destek açısından avantajlıdır. Dışta yer alması eğilmeye karşı kaldıraç gibi direnç sağlar."},{"t":"İşlevle ilişki","a":"Esnek destek","d":"Dış kenardaki esnek kollenkima, sapın dik durmasını ama yine de eğilebilmesini sağlar. Bu, hâlâ büyüyen sap için idealdir."}],"ans":"Kollenkima (dışta yer alarak esnek destek sağlar)"}]},"lise":{"kolay":[{"q":"Kollenkima dokusunun hücre yapısı, canlılık durumu ve temel görevini adım adım açıklayarak bu dokuyu tanımlayalım.","steps":[{"t":"Hücre yapısı","a":"Köşe kalınlaşması","d":"Kollenkima hücrelerinin çeperleri özellikle köşelerden kalınlaşmıştır. Bu kalınlaşma selülozca zengindir ve düzensiz dağılır."},{"t":"Canlılık durumu","a":"Canlı hücreler","d":"Kollenkima hücreleri olgunlukta bile canlıdır. Çeperleri tam olarak ligninleşmediği için protoplastları korunur."},{"t":"Temel görev","a":"Esnek destek","d":"Kollenkima büyümeye devam eden organlara esnek destek sağlar. Canlı ve esnek olduğu için organ uzarken birlikte uzayabilir."}],"ans":"Kollenkima: canlı, köşeleri selülozla kalınlaşmış, esnek destek dokusu"},{"q":"Kollenkimanın hangi bitki organlarında bulunduğunu ve bu organlardaki konumunu adım adım açıklayalım.","steps":[{"t":"Bulunduğu organlar","a":"Genç gövde, yaprak sapı, damar","d":"Kollenkima genç gövdelerde, yaprak saplarında ve yaprak damarlarında bulunur. Bu organlar büyümeye devam ettiği için esnek desteğe ihtiyaç duyar."},{"t":"Gövdedeki konumu","a":"Epidermis altında","d":"Genç gövdede kollenkima genellikle epidermisin hemen altında, köşelerde demetler hâlinde yer alır. Bu dış konum desteği güçlendirir."},{"t":"Konumun avantajı","a":"Periferik destek","d":"Dışa yakın konum, eğilmeye karşı kaldıraç gibi direnç sağlar. Böylece az miktarda doku ile etkili destek elde edilir."}],"ans":"Genç gövde, yaprak sapı ve damarlarda; çoğunlukla epidermis altında"},{"q":"Kollenkima ve sklerenkimanın canlılık ve çeper bileşimi açısından farklarını adım adım karşılaştıralım.","steps":[{"t":"Canlılık farkı","a":"Canlı / ölü","d":"Kollenkima olgunlukta canlı kalır, sklerenkima ise olgunlukta ölüdür. Bu en temel ayırt edici özelliktir."},{"t":"Çeper bileşimi","a":"Selüloz / lignin","d":"Kollenkima çeperleri selülozca zengin, sklerenkima çeperleri ise ligninle kalınlaşmıştır. Lignin çepere sertlik ve dayanıklılık katar."},{"t":"İşlev farkı","a":"Esnek / sert destek","d":"Bu farklar nedeniyle kollenkima esnek destek, sklerenkima ise sert ve dayanıklı destek sağlar. İkisi farklı organ ve dönemlerde baskındır."}],"ans":"Kollenkima canlı/selülozlu/esnek, sklerenkima ölü/ligninli/sert"},{"q":"Kollenkima köşe kalınlaşmasının selülozdan oluşmasının doku esnekliğine etkisini adım adım açıklayalım.","steps":[{"t":"Kalınlaşma maddesi","a":"Selüloz","d":"Kollenkimanın köşe kalınlaşması selülozca zengindir. Selüloz, glikoz birimlerinden oluşan esnek bir polisakkarittir."},{"t":"Selülozun esnekliği","a":"Esnek polimer","d":"Selüloz, lignine göre daha esnek bir yapıya sahiptir. Bu yüzden selülozla kalınlaşan çeper esnekliğini korur."},{"t":"Doku esnekliğine etkisi","a":"Eğilebilir destek","d":"Selüloz esnek olduğu için kollenkima eğilebilir ama yine de destek verir. Bu sayede büyüyen organ esnekliğini kaybetmeden desteklenir."}],"ans":"Selüloz esnek olduğundan kollenkima eğilebilir destek sağlar"},{"q":"Kollenkimanın büyümeye devam eden organlar için neden ideal bir destek dokusu olduğunu adım adım açıklayalım.","steps":[{"t":"Büyüyen organın ihtiyacı","a":"Esnek destek gerekir","d":"Büyümeye devam eden organlar uzamaktadır. Sert ve katı bir destek bu uzamayı kısıtlayacağı için esnek bir destek gerekir."},{"t":"Kollenkimanın esnekliği","a":"Canlı ve esnek","d":"Kollenkima canlı hücrelerden oluştuğu için esnektir ve organ uzarken birlikte uzayabilir. Çeperi tam ligninleşmediğinden plastikliğini korur."},{"t":"İdeal olma nedeni","a":"Destek ve büyüme uyumu","d":"Kollenkima hem destek verir hem de büyümeyi engellemez. Bu denge, onu genç organlar için ideal destek dokusu yapar."}],"ans":"Esnek ve canlı olduğundan büyümeyi engellemeden destek verir"},{"q":"Kollenkima hücrelerinin köşe (angüler), çeper (lameller) ve boşluk (laküner) tipi kalınlaşmalarını adım adım açıklayalım.","steps":[{"t":"Köşe kalınlaşması","a":"Angüler kollenkima","d":"En yaygın tip köşe kalınlaşmasıdır ve angüler kollenkima denir. Kalınlaşma hücrenin köşelerinde yoğunlaşır."},{"t":"Çeper kalınlaşması","a":"Lameller kollenkima","d":"Lameller tipte kalınlaşma teğet çeperlerde yoğunlaşır. Hücreler katmanlı bir görünüm kazanır."},{"t":"Boşluk kalınlaşması","a":"Laküner kollenkima","d":"Laküner tipte kalınlaşma hücreler arası boşlukların kenarında görülür. Tüm tiplerde ortak nokta esnek selüloz kalınlaşmasıdır."}],"ans":"Angüler (köşe), lameller (çeper) ve laküner (boşluk) kollenkima"},{"q":"Kollenkimanın meristem dokuyla ilişkisini ve genç organlardaki kökenini adım adım açıklayalım.","steps":[{"t":"Kökeni","a":"Meristemden gelişir","d":"Kollenkima, sürgün ucundaki birincil meristem hücrelerinin farklılaşmasıyla oluşur. Bu yüzden birincil bir dokudur."},{"t":"Genç organda gelişimi","a":"Erken farklılaşma","d":"Organ büyürken kollenkima erken farklılaşır ve esneklik kazanır. Böylece genç organ daha gelişirken destek alabilir."},{"t":"Büyümeye uyum","a":"Plastik çeper","d":"Kollenkima çeperi plastik olduğu için organ uzarken kalınlaşmaya devam edebilir. Bu, büyümeyle uyumlu bir destek sağlar."}],"ans":"Kollenkima birincil meristemden gelişen birincil destek dokusudur"},{"q":"Otsu (zarsı) bitkilerde kollenkimanın neden başlıca destek dokusu olduğunu adım adım açıklayalım.","steps":[{"t":"Otsu bitkinin özelliği","a":"Odun dokusu az","d":"Otsu bitkilerde sertleşmiş odun dokusu çok azdır veya yoktur. Bu yüzden başka bir destek mekanizmasına ihtiyaç duyarlar."},{"t":"Turgor ve kollenkima","a":"Esnek destek","d":"Otsu bitkiler dik durmak için turgor basıncı ve kollenkimaya dayanır. Kollenkima, esnek destekle gövdeyi ayakta tutar."},{"t":"Sonuç","a":"Başlıca destek","d":"Odun dokusu yetersiz olduğundan kollenkima otsu bitkilerde başlıca destek dokusudur. Esnek destek, otsu gövdeler için yeterlidir."}],"ans":"Otsu bitkilerde odun az olduğundan kollenkima başlıca destek dokusudur"},{"q":"Kollenkima hücrelerinin uzun ve diri kalmasının fotosentez ile ilişkisini adım adım açıklayalım.","steps":[{"t":"Hücrelerin canlılığı","a":"Canlı protoplast","d":"Kollenkima hücreleri canlı protoplasta sahiptir. Bu nedenle metabolik olarak aktiftirler."},{"t":"Kloroplast içermesi","a":"Bazıları kloroplastlı","d":"Özellikle yüzeye yakın kollenkima hücreleri kloroplast içerebilir. Bu, onların fotosentez yapabildiğini gösterir."},{"t":"İşlevsel sonuç","a":"Destek + fotosentez","d":"Bu hücreler hem destek hem sınırlı fotosentez yapabilir. Canlı olmaları bu çift işlevi mümkün kılar."}],"ans":"Canlı oldukları için bazı kollenkima hücreleri fotosentez de yapabilir"},{"q":"Kollenkimanın enine kesitte tanınması için kullanılacak üç temel ölçütü adım adım belirleyelim.","steps":[{"t":"Birinci ölçüt","a":"Köşe kalınlaşması","d":"Kesitte hücre köşelerinde düzensiz kalınlaşma görülmesi kollenkimanın ilk işaretidir. Bu, parlak köşeler hâlinde belirir."},{"t":"İkinci ölçüt","a":"Canlı protoplast","d":"Hücrelerin içinde sitoplazma ve çekirdek görülmesi canlılığı gösterir. Bu özellik onu ölü sklerenkimadan ayırır."},{"t":"Üçüncü ölçüt","a":"Konum","d":"Epidermis altında, demetler hâlinde periferik konum üçüncü ölçüttür. Bu üç ölçüt birlikte kollenkimayı kesinleştirir."}],"ans":"Köşe kalınlaşması, canlı protoplast ve periferik konum"},{"q":"Kollenkimanın çeper kalınlaşmasının düzgün olmamasının (eşit dağılmamasının) işlevsel anlamını adım adım açıklayalım.","steps":[{"t":"Kalınlaşmanın düzensizliği","a":"Köşelerde yoğun","d":"Kollenkimada kalınlaşma çeper boyunca eşit değildir, köşelerde yoğunlaşır. Bu düzensizlik dokunun karakteristiğidir."},{"t":"Esnekliğe etkisi","a":"İnce bölgeler esner","d":"Çeperin ince kalan bölgeleri esnemeye izin verir. Köşelerdeki kalın bölgeler ise yapısal desteği sağlar."},{"t":"İşlevsel anlam","a":"Esnek + dayanıklı","d":"Bu dağılım, dokunun hem esnek hem destekleyici olmasını sağlar. Böylece organ hem eğilebilir hem ayakta kalabilir."}],"ans":"Köşede kalın, çeperde ince yapı esneklik ve desteği birlikte sağlar"},{"q":"Kollenkimanın yaprak orta damarındaki konumunu ve buradaki işlevini adım adım açıklayalım.","steps":[{"t":"Orta damarın yapısı","a":"Yaprağın iskeleti","d":"Yaprağın orta damarı, yaprağı taşıyan ana destek yapısıdır. Bu bölge mekanik olarak güçlü olmalıdır."},{"t":"Kollenkimanın konumu","a":"Damarın üst-alt yüzünde","d":"Kollenkima orta damarın üst ve alt yüzeylerine yakın yerleşir. Bu konum eğilmeye karşı destek sağlar."},{"t":"İşlevi","a":"Esnek destek","d":"Buradaki kollenkima yaprağın düz ve açık durmasını sağlar. Esnek olduğu için yaprak rüzgârda kıvrılsa bile kırılmaz."}],"ans":"Orta damarın üst-alt yüzünde yer alıp yaprağa esnek destek verir"},{"q":"Kollenkimanın su durumuyla (turgor) ilişkisini ve su kaybında destek yeteneğine etkisini adım adım açıklayalım.","steps":[{"t":"Turgorun etkisi","a":"Su ile dolu hücre","d":"Kollenkima hücreleri canlı olduğundan su ile dolarak turgor kazanır. Turgorlu hücreler daha sert ve destekleyici olur."},{"t":"Su kaybının etkisi","a":"Destek azalır","d":"Bitki su kaybedince kollenkima hücrelerinin turgoru düşer. Bu durumda destek yeteneği bir miktar azalır."},{"t":"Sonuç","a":"Turgora kısmen bağımlı","d":"Kollenkima desteği kısmen turgora bağlıdır. Bu yüzden susuz kalan otsu bitkiler pörsür ve dik duramaz."}],"ans":"Kollenkima desteği kısmen turgora bağlıdır; su kaybında azalır"},{"q":"Kollenkima neden tek başına büyük ağaçların gövdesini taşıyamaz; bunu adım adım açıklayalım.","steps":[{"t":"Ağaç gövdesinin yükü","a":"Çok ağır yük","d":"Büyük ağaç gövdeleri çok ağır yapılardır ve büyük mekanik yük taşır. Bu yük için çok dayanıklı bir destek gerekir."},{"t":"Kollenkimanın sınırı","a":"Esnek ama az dayanıklı","d":"Kollenkima esnektir ama çok ağır yükleri taşıyacak sertlikte değildir. Çeperi tam ligninleşmediği için yapısal sınırı vardır."},{"t":"Çözüm","a":"Odun dokusu","d":"Ağaçlarda asıl yük taşıma işini ligninleşmiş odun (ksilem) ve sklerenkima üstlenir. Kollenkima yalnızca genç bölgelerde destekçidir."}],"ans":"Kollenkima esnek ama yeterince sert olmadığından ağır yükü odun taşır"},{"q":"Kollenkimanın gelişim sırasında bazen sklerenkimaya benzer biçimde sertleşebilmesini adım adım açıklayalım.","steps":[{"t":"Başlangıç durumu","a":"Esnek kollenkima","d":"Kollenkima başlangıçta canlı ve esnek bir destek dokusudur. Çeperi selülozca zengindir."},{"t":"Olgunlaşma süreci","a":"Lignin birikebilir","d":"Bazı durumlarda yaşlanan kollenkima çeperinde lignin birikmeye başlayabilir. Bu, çeperi sertleştirir."},{"t":"Sonuç","a":"Sklerenkimaya geçiş","d":"Lignin biriken kollenkima, yapı ve işlev bakımından sklerenkimaya benzer hâle gelebilir. Böylece esnek destekten sert desteğe geçiş olur."}],"ans":"Yaşlanan kollenkima çeperinde lignin birikerek sklerenkimaya dönüşebilir"}],"zor":[{"q":"Bir botanikçi enine kesitte epidermis altında köşeleri belirgin kalınlaşmış, canlı protoplastlı, sürekli demetler oluşturan hücreler gözlemliyor. Bu dokuyu kanıtlarıyla belirleyip işlevini adım adım açıklayalım.","steps":[{"t":"Köşe kalınlaşması","a":"Angüler tip","d":"Köşelerde belirgin kalınlaşma, angüler kollenkimanın tipik göstergesidir. Bu kalınlaşma selülozdan oluşur ve düzensizdir."},{"t":"Canlı protoplast","a":"Kollenkima kanıtı","d":"Hücrelerin canlı protoplasta sahip olması bu dokunun kollenkima olduğunu doğrular. Sklerenkima olgunlukta ölü olacağından elenir."},{"t":"Konum","a":"Periferik destek","d":"Epidermis altında demetler hâlinde dış konum, eğilmeye karşı kaldıraç desteği sağlar. Bu konum mekanik açıdan verimlidir."},{"t":"İşlev","a":"Esnek destek","d":"Tüm bulgular kollenkimanın genç organa esnek destek verdiğini gösterir. Organ büyürken bu destek esnekliğiyle uyum sağlar."}],"ans":"Angüler kollenkima (canlı, selülozlu, periferik esnek destek)"},{"q":"Bir öğrenci kollenkima ve sklerenkimanın aynı gövdede farklı bölgelerde bulunduğunu görüyor. İki dokunun çeper bileşimi, canlılık, konum ve işlev farklarını adım adım karşılaştıralım.","steps":[{"t":"Çeper bileşimi","a":"Selüloz / lignin","d":"Kollenkima selülozca zengin çeperle, sklerenkima ligninle kalınlaşır. Lignin sertlik, selüloz esneklik sağlar."},{"t":"Canlılık","a":"Canlı / ölü","d":"Kollenkima olgunlukta canlıdır, sklerenkima ise ölüdür. Bu temel fizyolojik farktır."},{"t":"Konum","a":"Genç dış / olgun iç","d":"Kollenkima genellikle genç organın dış bölgesinde, sklerenkima ise olgun organın daha iç ve dağınık bölgelerinde bulunur."},{"t":"İşlev","a":"Esnek / kalıcı sert destek","d":"Kollenkima büyürken esnek destek, sklerenkima büyüme bitince kalıcı sert destek verir. İkisi farklı gelişim dönemlerine hizmet eder."}],"ans":"Kollenkima canlı/selülozlu/esnek, sklerenkima ölü/ligninli/sert destek"},{"q":"Bir bitki fizyoloğu, hareketli ortamda büyüyen bitkilerin (örneğin rüzgârlı bölgelerde) gövdelerinde kollenkimanın daha bol geliştiğini buluyor. Bu uyumu kollenkimanın mekanik özellikleriyle adım adım açıklayalım.","steps":[{"t":"Mekanik uyaran","a":"Eğilme kuvveti","d":"Rüzgâr gibi hareketli ortamlar gövdeyi sürekli eğilmeye zorlar. Bu, gövdeye tekrarlayan mekanik kuvvet uygular."},{"t":"Tigmomorfogenez","a":"Mekanik uyaranla gelişim","d":"Bitkiler mekanik uyarana yapısal değişiklikle yanıt verir; buna tigmomorfogenez denir. Eğilen gövdeler genelde kısa ve kalın gelişir."},{"t":"Kollenkima artışı","a":"Esnek direnç","d":"Bitki, eğilmeye dayanmak için esnek destek dokusunu artırır. Kollenkima eğilip kırılmadığı için bu role uygundur."},{"t":"Sonuç","a":"Mekanik adaptasyon","d":"Sonuçta gövde, kollenkima artışıyla rüzgâra dayanıklı hâle gelir. Esnek destek, eğilme stresini emerek kırılmayı önler."}],"ans":"Esnek destek sağladığından mekanik strese yanıt olarak kollenkima artar"},{"q":"Bir araştırmacı, kollenkima çeperinin plastik (kalıcı) deformasyon gösterebildiğini ölçüyor. Bu özelliğin büyüyen organın uzamasıyla ilişkisini adım adım açıklayalım.","steps":[{"t":"Plastik deformasyon","a":"Kalıcı uzama","d":"Plastik deformasyon, çepere uygulanan kuvvet kalktığında bile şeklin kalıcı değişmesidir. Kollenkima çeperi bu davranışı gösterebilir."},{"t":"Büyümeyle ilişki","a":"Çeper uzayabilir","d":"Organ uzarken hücre çeperinin de kalıcı olarak uzaması gerekir. Kollenkimanın plastik çeperi bu uzamaya izin verir."},{"t":"Selülozun rolü","a":"Esnek matris","d":"Selülozca zengin çeper, ligninleşmediği için plastik kalır. Bu yüzden çeper uzarken bile destek vermeye devam eder."},{"t":"Sonuç","a":"Büyümeyle uyumlu destek","d":"Kollenkima, plastik çeperi sayesinde büyüyen organla birlikte uzar. Böylece destekle büyümeyi aynı anda sağlar."}],"ans":"Plastik çeperi sayesinde organ uzarken kollenkima da uzayıp destek verir"},{"q":"Bir laboratuvarda iki destek dokusu örneğine lignin boyası uygulanıyor; biri boyanırken diğeri boyanmıyor. Boyanmayan örneğin kollenkima olduğunu kanıtlayarak nedenini adım adım açıklayalım.","steps":[{"t":"Lignin boyası","a":"Lignini gösterir","d":"Lignin boyası (örneğin floroglusinol) ligninli çeperleri kırmızıya boyar. Boyanma, çeperde lignin olduğunu gösterir."},{"t":"Boyanan örnek","a":"Sklerenkima","d":"Boyanan örnek lignin içeriyordur, yani sklerenkimadır. Sklerenkima çeperleri ligninle kalınlaşmıştır."},{"t":"Boyanmayan örnek","a":"Kollenkima","d":"Boyanmayan örnek lignin içermiyordur. Kollenkima çeperi selülozca zengin olup ligninleşmediği için boyanmaz."},{"t":"Sonuç","a":"Selülozlu çeper","d":"Boyanmayan örnek kollenkimadır; çünkü çeperi esnek selülozdan oluşur. Bu da onun canlı ve esnek kalmasını sağlar."}],"ans":"Boyanmayan örnek kollenkimadır (çeperi ligninsiz, selülozludur)"},{"q":"Bir öğrenci, kollenkima hücrelerinin uzun ve dar prizmatik biçimini gözlemliyor. Bu hücre biçiminin destek işleviyle ilişkisini adım adım açıklayalım.","steps":[{"t":"Hücre biçimi","a":"Uzun, prizmatik","d":"Kollenkima hücreleri genellikle uzun eksen boyunca uzamış, prizmatik hücrelerdir. Bu biçim organın uzun ekseniyle hizalanır."},{"t":"Yön ile ilişki","a":"Eksen boyunca destek","d":"Hücrelerin organın uzun ekseni boyunca dizilmesi, eksenel desteği güçlendirir. Bu, gövdenin dik durmasına yardımcı olur."},{"t":"Esneklikle birleşmesi","a":"Eğilmeye direnç","d":"Uzun hücreler aynı zamanda esnektir, bu yüzden eğilmeye direnç gösterir ama kırılmaz. Biçim ve esneklik birlikte etkili destek sağlar."}],"ans":"Uzun prizmatik biçim eksenel desteği güçlendirir ve esnek kalmayı sağlar"},{"q":"Bir bitki gelişim sürecinde organ önce uzar, sonra olgunlaşıp büyümesi durur. Bu süreçte kollenkimadan sklerenkimaya destek geçişini adım adım açıklayalım.","steps":[{"t":"Uzama dönemi","a":"Kollenkima baskın","d":"Organ uzarken esnek desteğe ihtiyaç vardır. Bu dönemde kollenkima baskındır çünkü uzamayı engellemez."},{"t":"Büyümenin durması","a":"Sert destek ihtiyacı","d":"Organ olgunlaşıp büyümesi durunca artık esnekliğe gerek kalmaz. Bunun yerine kalıcı ve dayanıklı desteğe ihtiyaç doğar."},{"t":"Sklerenkima oluşumu","a":"Lignin birikimi","d":"Olgunlaşan organda lignin biriken sklerenkima hücreleri gelişir. Bu hücreler ölü ve sert destek sağlar."},{"t":"Geçişin mantığı","a":"Büyüme-destek dengesi","d":"Bu geçiş, büyüme ile dayanıklılık arasındaki dengeyi yansıtır. Önce esneklik, sonra dayanıklılık öncelik kazanır."}],"ans":"Uzama döneminde kollenkima, olgunlukta sklerenkima destek sağlar"},{"q":"Bir öğrenci kollenkimanın hidratasyon (su tutma) kapasitesinin yüksek olduğunu öğreniyor. Bu özelliğin esneklik ve destek işleviyle ilişkisini adım adım açıklayalım.","steps":[{"t":"Hidratasyon kapasitesi","a":"Su tutar","d":"Kollenkima çeperi yüksek oranda su tutabilir. Bu, selülozca zengin ve pektince yüksek çeper yapısından kaynaklanır."},{"t":"Su ve esneklik","a":"Hidratlı çeper esnek","d":"Su tutan çeper daha esnek ve plastik kalır. Bu, dokunun eğilebilmesini ve uzayabilmesini sağlar."},{"t":"Destekle ilişki","a":"Turgor ve esneklik","d":"Hidrate çeper ve turgor birlikte destek sağlar. Su kaybında bu destek azalır, bu yüzden kollenkima desteği su durumuna kısmen bağlıdır."}],"ans":"Yüksek hidratasyon çeperi esnek tutar; destek su durumuna kısmen bağlıdır"},{"q":"Bir botanik incelemesinde, kereviz sapındaki belirgin ipliksi yapıların kollenkima olduğu, dış kenara yakın demetler oluşturduğu görülüyor. Bu konumun mekanik avantajını adım adım açıklayalım.","steps":[{"t":"İpliksi yapının kimliği","a":"Kollenkima demetleri","d":"Kerevizdeki ipliksi yapılar köşeleri kalınlaşmış canlı kollenkima demetleridir. Bu, sapın esnek destek dokusudur."},{"t":"Dış konum","a":"Periferik yerleşim","d":"Bu demetler sapın dış kenarına yakın yerleşmiştir. Dışta olmaları eğilme momentine karşı daha etkilidir."},{"t":"Mekanik avantaj","a":"Kiriş etkisi","d":"Dışa yerleşen destek, bir kirişin kenarlarına malzeme koymak gibi eğilmeye karşı direnci artırır. Böylece az dokuyla yüksek destek elde edilir."},{"t":"Sonuç","a":"Verimli esnek destek","d":"Periferik kollenkima, sapın hem dik durmasını hem esnek kalmasını verimli biçimde sağlar. Bu, hâlâ büyüyen sap için idealdir."}],"ans":"Periferik konum eğilmeye karşı direnci artırarak verimli destek sağlar"},{"q":"Bir araştırmacı, kollenkimanın hücre bölünmesi geçirebilen az farklılaşmış bir doku olduğunu gözlemliyor. Bu özelliğin yara onarımı ve ikincil meristem oluşumuyla ilişkisini adım adım açıklayalım.","steps":[{"t":"Az farklılaşma","a":"Bölünebilen canlı hücre","d":"Kollenkima hücreleri canlı ve nispeten az farklılaşmıştır. Bu nedenle uygun koşulda tekrar bölünebilirler."},{"t":"Yara onarımı","a":"Yeni hücre üretimi","d":"Doku zedelendiğinde kollenkima hücreleri bölünerek yeni hücreler üretebilir. Bu, yaranın onarılmasına katkı sağlar."},{"t":"İkincil meristem","a":"Meristeme dönüşebilme","d":"Bazı durumlarda kollenkima hücreleri bölünme yeteneği kazanarak ikincil meristem (kambiyum) oluşumuna katılabilir. Bu, canlı kalmalarının bir avantajıdır."},{"t":"Sonuç","a":"Esneklik + yenilenme","d":"Kollenkima hem esnek destek verir hem de canlı olduğu için yenilenme potansiyeli taşır. Bu çift yetenek sklerenkimada bulunmaz."}],"ans":"Canlı ve az farklılaşmış olduğundan bölünüp yara onarımına katılabilir"},{"q":"Bir öğrenci, kollenkimanın çeperinde selüloz yanında bol miktarda pektin bulunduğunu öğreniyor. Pektinin esneklik ve su tutma üzerindeki etkisini adım adım açıklayalım.","steps":[{"t":"Çeper bileşimi","a":"Selüloz + pektin","d":"Kollenkima çeperi selüloz ve yüksek oranda pektin içerir. Pektin, çeperde jel benzeri bir matris oluşturur."},{"t":"Su tutma","a":"Pektin su bağlar","d":"Pektin yüksek oranda su bağlayabilir. Bu, çeperin hidrate ve esnek kalmasına katkı sağlar."},{"t":"Esnekliğe etki","a":"Plastik matris","d":"Pektince zengin, hidrate çeper plastik ve esnek kalır. Bu yüzden kollenkima eğilebilir ve organ büyürken uzayabilir."},{"t":"Sonuç","a":"Esnek destek","d":"Pektin ve selülozun birlikteliği kollenkimaya esneklik kazandırır. Bu, ligninleşmiş sklerenkimanın sertliğinden temel farktır."}],"ans":"Pektin su tutarak çeperi hidrate ve esnek tutar; bu da esnek destek sağlar"},{"q":"Bir bitki mühendisi, sera bitkilerinin rüzgârsız ortamda incecik ve zayıf gövdeli geliştiğini gözlemliyor. Bu durumu kollenkima gelişimi açısından adım adım açıklayalım.","steps":[{"t":"Rüzgârsız ortam","a":"Mekanik uyaran yok","d":"Serada rüzgâr olmadığı için gövdeye eğilme kuvveti uygulanmaz. Mekanik uyaran eksikliği gelişim sinyalini azaltır."},{"t":"Kollenkima gelişimi","a":"Az destek dokusu","d":"Mekanik uyaran olmayınca bitki daha az kollenkima geliştirir. Çünkü esnek desteğe duyulan ihtiyaç algılanmaz."},{"t":"Sonuç","a":"Zayıf, ince gövde","d":"Az kollenkima nedeniyle gövde ince ve zayıf kalır. Dış ortama çıkarıldığında bu bitkiler kolayca eğilip kırılabilir."}],"ans":"Mekanik uyaran olmadığından kollenkima az gelişir, gövde zayıf kalır"},{"q":"Bir kesitte iki bitişik destek bölgesi görülüyor: dış bölge canlı ve köşe kalınlaşmalı, iç bölge ölü ve tamamen ligninli. Her bölgeyi tanımlayıp gelişimsel sırayı adım adım açıklayalım.","steps":[{"t":"Dış bölge","a":"Kollenkima","d":"Canlı ve köşeleri kalınlaşmış dış bölge kollenkimadır. Selülozlu çeperiyle esnek destek sağlar."},{"t":"İç bölge","a":"Sklerenkima","d":"Ölü ve tamamen ligninli iç bölge sklerenkimadır. Ligninli çeperiyle sert ve kalıcı destek sağlar."},{"t":"Gelişimsel sıra","a":"Önce kollenkima","d":"Genç organda önce esnek kollenkima gelişir; organ olgunlaşınca sklerenkima eklenir. Bu sıra, büyüme ile dayanıklılık dengesini yansıtır."},{"t":"Sonuç","a":"Tamamlayıcı destek","d":"Kollenkima ve sklerenkima birlikte tamamlayıcı destek oluşturur. Biri esneklik, diğeri dayanıklılık katar."}],"ans":"Dış: kollenkima (canlı/esnek), iç: sklerenkima (ölü/sert); önce kollenkima gelişir"},{"q":"Bir öğrenci, kollenkimanın eğilme stresini emerek gövdenin kırılmasını önlediğini öğreniyor. Bu davranışı malzeme dayanıklılığı açısından adım adım açıklayalım.","steps":[{"t":"Eğilme stresi","a":"Mekanik gerilim","d":"Gövde eğildiğinde dış yüzeyde gerilme, iç yüzeyde sıkışma oluşur. Bu mekanik gerilim malzemeyi zorlar."},{"t":"Kollenkimanın yanıtı","a":"Esnek deformasyon","d":"Esnek kollenkima bu gerilim altında kırılmadan deforme olabilir. Esnekliği sayesinde stresi emerek dağıtır."},{"t":"Kırılmanın önlenmesi","a":"Enerji sönümleme","d":"Esnek doku, eğilme enerjisini sönümleyerek ani kırılmayı önler. Sert ve gevrek bir doku bu enerjiyi ememez ve çatlardı."},{"t":"Sonuç","a":"Tokluk sağlar","d":"Kollenkima gövdeye tokluk (kırılmaya direnç) kazandırır. Böylece gövde eğilse bile bütünlüğünü korur."}],"ans":"Esnekliğiyle eğilme stresini emer, enerjiyi sönümleyip kırılmayı önler"},{"q":"Bir araştırmacı kollenkima ve sklerenkimanın hangi gelişim dönemlerinde ve hangi mekanik koşullarda öne çıktığını karşılaştırıyor. Bu iki dokunun işlevsel iş bölümünü adım adım açıklayalım.","steps":[{"t":"Kollenkimanın dönemi","a":"Genç, büyüyen organ","d":"Kollenkima genç ve hâlâ büyüyen organlarda öne çıkar. Esnek olduğu için büyümeyi engellemeden destek verir."},{"t":"Sklerenkimanın dönemi","a":"Olgun, büyümesi durmuş organ","d":"Sklerenkima olgun ve büyümesi durmuş organlarda öne çıkar. Ligninli ve sert olduğu için kalıcı, dayanıklı destek verir."},{"t":"Mekanik koşul","a":"Esneklik / dayanıklılık","d":"Dinamik eğilme koşullarında esnek kollenkima, statik ağır yük koşullarında sert sklerenkima avantajlıdır. Her biri farklı bir mekanik probleme çözümdür."},{"t":"İş bölümü","a":"Tamamlayıcı destek","d":"İki doku bir iş bölümü oluşturur: kollenkima erken/dinamik destek, sklerenkima geç/statik destek sağlar. Birlikte bitkinin bütüncül desteğini kurarlar."}],"ans":"Kollenkima genç/dinamik esnek destek, sklerenkima olgun/statik sert destek verir"}]}},"sklerenkima":{"ilkokul":{"kolay":[{"q":"Bir cevizin sert kabuğunu kırmak için tokmak gerekir. Bu kabuğu bu kadar sert yapan, ölü ve dayanıklı hücrelerden oluşan doku hangisidir? Adım adım bulalım.","steps":[{"t":"Kabuğun sertliği","a":"Çok sert kabuk","d":"Ceviz kabuğu çok serttir ve elle kolayca kırılmaz. Bu sertliği sağlayan özel bir doku vardır."},{"t":"Sert dokunun adı","a":"Ölü, sert hücreler","d":"Bu doku ölü ve çok kalın çeperli hücrelerden oluşur. Sert destek veren bu doku sklerenkimadır."}],"ans":"Sklerenkima (sert doku)"},{"q":"Armut yerken dişimize taneli, sert parçacıklar gelir. Bu sert taş hücrelerini oluşturan dokunun adı nedir? Adım adım düşünelim.","steps":[{"t":"Taneli parçacıklar","a":"Sert taş hücreleri","d":"Armudun içindeki sert, taneli yapılar taş hücreleridir. Bunlar çok kalın ve sert çeperlere sahiptir."},{"t":"Dokunun adı","a":"Sklerenkima","d":"Taş hücreleri (sklereitler) sklerenkima dokusunun bir çeşididir. Bu doku sert ve dayanıklı destek verir."}],"ans":"Sklerenkima"},{"q":"Olgun ve büyümesi durmuş bir bitki organına sağlam, sert destek veren ölü hücrelerden oluşan doku hangisidir? Birlikte bulalım.","steps":[{"t":"Olgun organın ihtiyacı","a":"Sağlam destek","d":"Büyümesi durmuş olgun organlar artık uzamadığı için sert ve kalıcı bir desteğe ihtiyaç duyar. Bu destek dayanıklı olmalıdır."},{"t":"Uygun doku","a":"Ölü, sert hücreler","d":"Bu sağlam desteği ölü ve sert çeperli sklerenkima sağlar. Hücreleri ölü olduğu için içleri boş kalır ve sadece sert çeper kalır."}],"ans":"Sklerenkima"},{"q":"Keten ve kenevir gibi bitkilerden sağlam ipler yapılır. Bu bitkilerdeki uzun, dayanıklı lifleri oluşturan doku hangisidir? Adım adım bulalım.","steps":[{"t":"Sağlam lifler","a":"Uzun, güçlü lifler","d":"Keten ve kenevir bitkilerinde uzun ve çok dayanıklı lifler bulunur. Bu lifler iplik ve halat yapımında kullanılır."},{"t":"Lif dokusunun adı","a":"Sklerenkima lifleri","d":"Bu uzun, sert liflere sklerenkima lifleri denir. Sklerenkima dokusunun bir çeşididir ve çok dayanıklıdır."}],"ans":"Sklerenkima (lifler)"},{"q":"Bir meyvenin sert çekirdek kabuğu, içindeki tohumu korur. Bu çok sert koruyucu kabuğu oluşturan ölü hücre dokusu hangisidir? Adım adım bulalım.","steps":[{"t":"Çekirdek kabuğu","a":"Sert koruma","d":"Meyve çekirdeklerinin sert kabuğu tohumu korur. Bu kabuk çok sert ve dayanıklıdır."},{"t":"Dokunun adı","a":"Sert taş hücreleri","d":"Bu sert kabuk, kalın çeperli ölü taş hücrelerinden oluşur. Bu hücreler sklerenkima dokusuna aittir."}],"ans":"Sklerenkima"}],"zor":[{"q":"Bir öğrenci mikroskopta bir destek dokusu inceliyor; hücrelerin içi boş, çeperleri çok kalın ve hücreler ölü görünüyor. Bu doku hangisidir ve neden bu kadar serttir? Adım adım çözelim.","steps":[{"t":"Hücrelerin ölü olması","a":"İçi boş hücreler","d":"Hücrelerin içinin boş ve ölü görünmesi önemli bir ipucudur. Çünkü bazı destek dokuları olgunlukta ölür."},{"t":"Çeperin kalınlığı","a":"Çok kalın çeper","d":"Hücre çeperlerinin çok kalın olması, dokunun sert ve dayanıklı olduğunu gösterir. Bu kalınlaşma ligninden oluşur."},{"t":"Dokunun belirlenmesi","a":"Sklerenkima","d":"Ölü ve kalın ligninli çeperli bu doku sklerenkimadır. Lignin dokuyu çok sert ve dayanıklı yapar."}],"ans":"Sklerenkima (kalın ligninli çeper sertliği sağlar)"},{"q":"Armudun içindeki sert taneli parçacıkların yuvarlak, çok kalın çeperli ölü hücreler olduğu görülüyor. Bu hücrelerin özel adı nedir ve hangi dokuya aittir? Adım adım bulalım.","steps":[{"t":"Hücrelerin görünümü","a":"Yuvarlak, kalın çeperli","d":"Armuttaki sert hücreler yuvarlakça ve çok kalın çeperlidir. Bu yapı onları sert ve taneli yapar."},{"t":"Özel adı","a":"Sklereit (taş hücresi)","d":"Bu kısa, yuvarlakça sert hücrelere sklereit ya da taş hücresi denir. Lifler ise uzun ve incedir, sklereitler kısadır."},{"t":"Ait olduğu doku","a":"Sklerenkima","d":"Sklereitler sklerenkima dokusunun bir çeşididir. Bu doku ligninli çeperleriyle sert destek sağlar."}],"ans":"Sklereit (taş hücresi); sklerenkima dokusuna aittir"},{"q":"Bir bahçıvan, genç filizlerin esnek, olgun dalların ise sert olduğunu fark ediyor. Olgun, büyümesi durmuş organlara sert destek veren doku hangisidir ve hücreleri canlı mıdır? Çözelim.","steps":[{"t":"Olgun dalın sertliği","a":"Sert ve dayanıklı","d":"Olgun dallar artık büyümediği için sert ve dayanıklıdır. Bu sertlik kalıcı bir destek dokusundan gelir."},{"t":"Dokunun adı","a":"Sklerenkima","d":"Olgun organlara sert destek veren doku sklerenkimadır. Genç organlardaki esnek kollenkimadan farklıdır."},{"t":"Hücrelerin durumu","a":"Ölü hücreler","d":"Sklerenkima hücreleri olgunlukta ölüdür. Çeperleri ligninle dolduğundan içlerindeki canlı kısım yok olur, geriye sert çeper kalır."}],"ans":"Sklerenkima (hücreleri olgunlukta ölüdür)"},{"q":"Bir öğrenci, sklerenkima ve kollenkimanın hangisinin esnek hangisinin sert olduğunu karıştırıyor. İki dokuyu sertlik ve canlılık açısından adım adım ayıralım.","steps":[{"t":"Kollenkimanın özelliği","a":"Canlı ve esnek","d":"Kollenkima canlı hücrelerden oluşur ve esnektir. Genç, büyüyen organlara esnek destek verir."},{"t":"Sklerenkimanın özelliği","a":"Ölü ve sert","d":"Sklerenkima olgunlukta ölü hücrelerden oluşur ve serttir. Olgun organlara sert ve dayanıklı destek verir."},{"t":"Ayrım","a":"Sert olan sklerenkima","d":"Bu yüzden sert ve dayanıklı destek dokusu sklerenkimadır. Esnek ve canlı olan ise kollenkimadır."}],"ans":"Sklerenkima sert ve ölü, kollenkima esnek ve canlıdır"},{"q":"Keten bitkisinin gövdesinden çok uzun ve dayanıklı lifler elde ediliyor. Bu liflerin hangi dokuya ait olduğunu ve neden bu kadar sağlam olduğunu adım adım açıklayalım.","steps":[{"t":"Liflerin özelliği","a":"Uzun ve sağlam","d":"Keten lifleri çok uzun ve kopması zor liflerdir. İplik ve kumaş yapımında bu sağlamlıkları kullanılır."},{"t":"Dokunun adı","a":"Sklerenkima lifleri","d":"Bu uzun, dayanıklı lifler sklerenkima dokusunun lif tipidir. Sklereitlerden daha uzun ve inceeydirler."},{"t":"Sağlamlığın nedeni","a":"Ligninli kalın çeper","d":"Lifler çok kalın, ligninli çeperlere sahiptir. Lignin çepere sertlik ve gerilmeye karşı dayanıklılık katar."}],"ans":"Sklerenkima lifleri (kalın ligninli çeperleri sağlamlık verir)"}]},"ortaokul":{"kolay":[{"q":"Bitkilerde sert ve dayanıklı destek sağlayan, olgunlukta ölü hücrelerden oluşan doku hangisidir ve çeperleri hangi maddeyle kalınlaşmıştır? Adım adım belirleyelim.","steps":[{"t":"Dokunun özelliği","a":"Sert, ölü hücreler","d":"Bu destek dokusu olgunlukta ölü hücrelerden oluşur ve çok sert bir yapıya sahiptir. Olgun organlara dayanıklı destek verir."},{"t":"Çeper maddesi","a":"Lignin","d":"Hücre çeperleri ligninle kalınlaşmıştır. Lignin, çepere sertlik ve dayanıklılık kazandıran bir maddedir."}],"ans":"Sklerenkima (ligninle kalınlaşmış)"},{"q":"Sklerenkimanın iki temel hücre çeşidi olan lifler ve sklereitleri (taş hücreleri) adım adım karşılaştıralım.","steps":[{"t":"Lifler","a":"Uzun ve ince","d":"Sklerenkima lifleri uzun, ince ve sivri uçlu hücrelerdir. Keten ve kenevirdeki gibi dayanıklı destek ve esnemeye direnç sağlar."},{"t":"Sklereitler","a":"Kısa ve sert","d":"Sklereitler (taş hücreleri) kısa, yuvarlakça ve çok sert hücrelerdir. Armudun taneli yapısı ve sert kabuklar bunlardan oluşur."}],"ans":"Lifler uzun ve ince; sklereitler kısa ve sert taş hücreleridir"},{"q":"Sklerenkima hücrelerinin olgunlukta neden ölü olduğunu ve bunun destek işlevine etkisini adım adım açıklayalım.","steps":[{"t":"Ligninleşme","a":"Çeper ligninle dolar","d":"Sklerenkima çeperi olgunlaşırken ligninle iyice kalınlaşır. Bu kalınlaşma hücrenin iç boşluğunu daraltır."},{"t":"Hücrenin ölmesi","a":"Protoplast yok olur","d":"Çeper tamamen ligninleşince hücrenin canlı kısmı (protoplast) yok olur ve hücre ölür. Geriye sadece sert çeper kalır."}],"ans":"Lignin çeperi doldurunca hücre ölür; geriye sert çeper kalarak destek verir"},{"q":"Sklerenkimanın hangi tür organlarda (genç mi olgun mu) bulunduğunu ve nedenini adım adım açıklayalım.","steps":[{"t":"Sklerenkimanın özelliği","a":"Sert, esnek değil","d":"Sklerenkima serttir ve esnek değildir. Bu yüzden bir organın uzamasına izin vermez."},{"t":"Uygun organ","a":"Olgun organlar","d":"Sklerenkima büyümesi durmuş, olgun organlarda bulunur. Bu organlar artık uzamadığı için sert destek onları kısıtlamaz, aksine dayanıklılık verir."}],"ans":"Olgun, büyümesi durmuş organlarda bulunur"},{"q":"Lignin maddesinin sklerenkimaya sertlik kazandırmasını ve bunun selülozdan farkını adım adım açıklayalım.","steps":[{"t":"Ligninin özelliği","a":"Sert madde","d":"Lignin, hücre çeperini sertleştiren ve su geçirmez hâle getiren bir maddedir. Çepere mekanik dayanıklılık katar."},{"t":"Selülozdan farkı","a":"Lignin sert, selüloz esnek","d":"Selüloz esnek bir maddeyken lignin serttir. Bu yüzden ligninli sklerenkima sert, selülozlu kollenkima esnektir."}],"ans":"Lignin sertlik verir; selüloz esnektir, bu yüzden sklerenkima serttir"}],"zor":[{"q":"Bir öğrenci enine kesitte içi boş, çok kalın ligninli çeperli, uzun ve sivri uçlu ölü hücreler buluyor. Bu hücreleri tanımlayıp dokusunu ve işlevini adım adım belirleyelim.","steps":[{"t":"Çeper ve canlılık","a":"Kalın ligninli, ölü","d":"Çok kalın ligninli çeper ve ölü hücreler sklerenkimanın işaretidir. Lignin dokuyu sertleştirir."},{"t":"Hücre biçimi","a":"Uzun, sivri uçlu lif","d":"Hücrelerin uzun ve sivri uçlu olması bunların sklerenkima lifleri olduğunu gösterir. Sklereitler ise kısa olurdu."},{"t":"İşlev","a":"Sert destek","d":"Bu lifler olgun organlara sert ve dayanıklı destek sağlar. Aynı zamanda gerilmeye karşı direnç gösterir."}],"ans":"Sklerenkima lifleri (kalın ligninli, ölü, sert destek)"},{"q":"Bir bitki olgunlaştıkça genç dönemdeki esnek desteğini sert destekle değiştirir. Bu değişimde rol alan dokuları ve değişimin nedenini adım adım açıklayalım.","steps":[{"t":"Genç dönem","a":"Kollenkima esnek destek","d":"Genç organda büyüme devam ettiği için esnek destek gerekir; bunu kollenkima sağlar. Esneklik, büyümeyi engellemez."},{"t":"Olgun dönem","a":"Sklerenkima sert destek","d":"Organ olgunlaşıp büyümesi durunca artık kalıcı, sert desteğe ihtiyaç duyar. Bunu ligninli sklerenkima sağlar."},{"t":"Değişimin nedeni","a":"Büyümenin durması","d":"Esnek destekten sert desteğe geçiş, organın büyümesinin durmasıyla ilgilidir. Büyüme bitince dayanıklılık önceliklidir."}],"ans":"Kollenkimadan sklerenkimaya geçiş; çünkü büyüme durur ve dayanıklılık gerekir"},{"q":"Bir laboratuvarda bir destek dokusu lignin boyasıyla kırmızıya boyanırken diğeri boyanmıyor. Boyanan örneğin sklerenkima olduğunu kanıtlayıp nedenini adım adım açıklayalım.","steps":[{"t":"Lignin boyası","a":"Lignini gösterir","d":"Lignin boyası, çeperde lignin bulunan dokuları kırmızıya boyar. Boyanma, ligninin varlığını kanıtlar."},{"t":"Boyanan örnek","a":"Sklerenkima","d":"Boyanan örnek lignin içerdiği için sklerenkimadır. Sklerenkima çeperleri ligninle kalınlaşmıştır."},{"t":"Boyanmama nedeni","a":"Diğeri kollenkima","d":"Boyanmayan örnek lignin içermez, yani kollenkimadır. Kollenkima çeperi selülozludur ve ligninleşmez."}],"ans":"Boyanan örnek sklerenkimadır (çeperi ligninlidir)"},{"q":"Armuttaki taneli yapı ile keten lifini karşılaştıran bir öğrenci, ikisinin de sert ama farklı biçimde olduğunu görüyor. Bu iki sklerenkima hücre tipini biçim ve işlev açısından adım adım karşılaştıralım.","steps":[{"t":"Armuttaki yapı","a":"Sklereit (kısa)","d":"Armudun taneli sert yapısı kısa, yuvarlakça sklereitlerden (taş hücresi) oluşur. Sertlik ve koruma sağlar."},{"t":"Keten lifi","a":"Lif (uzun)","d":"Keten lifi ise uzun, ince ve sivri uçlu sklerenkima lifidir. Gerilmeye karşı direnç ve eksenel destek sağlar."},{"t":"Ortak ve farklı yön","a":"Aynı doku, farklı biçim","d":"İkisi de ligninli, ölü sklerenkima hücreleridir ama biçimleri farklıdır. Sklereit koruma/sertlik, lif gerilme direnci için uzmanlaşmıştır."}],"ans":"Sklereit kısa/sert koruyucu, lif uzun/gerilmeye dayanıklı; ikisi de sklerenkima"},{"q":"Bir gemici, halatlar için keten ve kenevir liflerinin tercih edildiğini öğreniyor. Bu liflerin gerilmeye karşı dayanıklılığını sklerenkima yapısıyla adım adım açıklayalım.","steps":[{"t":"Liflerin yapısı","a":"Uzun ligninli hücreler","d":"Keten ve kenevir lifleri uzun, kalın ligninli çeperli sklerenkima hücreleridir. Bu yapı onları çok dayanıklı yapar."},{"t":"Gerilme direnci","a":"Lignin dayanıklılık verir","d":"Lignin ve kalın çeper, lifin gerilmeye karşı kopmadan direnç göstermesini sağlar. Bu yüzden zorlanınca kolay kopmazlar."},{"t":"Halat için uygunluk","a":"Uzun ve sağlam","d":"Uzun ve gerilmeye dayanıklı lifler halat yapımına çok uygundur. Sklerenkima lifleri bu nedenle tercih edilir."}],"ans":"Uzun, ligninli sklerenkima lifleri gerilmeye dirençli olduğundan halat için idealdir"}]},"lise":{"kolay":[{"q":"Sklerenkima dokusunun hücre yapısı, canlılık durumu ve temel görevini adım adım açıklayarak bu dokuyu tanımlayalım.","steps":[{"t":"Hücre yapısı","a":"Kalın ligninli çeper","d":"Sklerenkima hücrelerinin çeperleri ligninle kalınlaşmıştır. Bu kalınlaşma çepere büyük sertlik ve dayanıklılık kazandırır."},{"t":"Canlılık durumu","a":"Olgunlukta ölü","d":"Sklerenkima hücreleri olgunlukta ölüdür. Çeper tamamen ligninleşince protoplast yok olur, geriye sert çeper kalır."},{"t":"Temel görev","a":"Sert destek","d":"Sklerenkima olgun, büyümesi durmuş organlara sağlam ve dayanıklı destek verir. Sertliği nedeniyle kalıcı mekanik destek sağlar."}],"ans":"Sklerenkima: olgunlukta ölü, ligninle kalınlaşmış, sert destek dokusu"},{"q":"Sklerenkimanın iki hücre tipi olan lifler ve sklereitlerin (taş hücresi) biçim ve bulunuş yerlerini adım adım karşılaştıralım.","steps":[{"t":"Lifler","a":"Uzun, ince, sivri","d":"Sklerenkima lifleri uzun, ince ve sivri uçlu hücrelerdir. Demetler hâlinde bulunup eksenel destek ve gerilme direnci sağlar."},{"t":"Sklereitler","a":"Kısa, izodiametrik","d":"Sklereitler kısa, çoğu izodiametrik (her yöne benzer boyutta) sert hücrelerdir. Armudun taneli yapısı, sert tohum kabukları bunlardan oluşur."},{"t":"Bulunuş yerleri","a":"Lif demet, sklereit dağınık","d":"Lifler genelde demetler hâlinde damar çevresinde, sklereitler ise dağınık ya da kümeler hâlinde meyve etinde ve kabuklarda bulunur."}],"ans":"Lifler uzun/demet hâlinde; sklereitler kısa/dağınık taş hücreleridir"},{"q":"Sklerenkimanın çeperinde ligninin rolünü ve bu maddenin dokuya kazandırdığı özellikleri adım adım açıklayalım.","steps":[{"t":"Ligninin yapısı","a":"Karmaşık polimer","d":"Lignin, fenolik birimlerden oluşan karmaşık bir polimerdir. Hücre çeperinde selülozun arasını doldurur."},{"t":"Sertlik kazandırması","a":"Mekanik dayanıklılık","d":"Lignin çepere sertlik ve sıkışmaya karşı dayanıklılık katar. Bu sayede sklerenkima ağır yükleri taşıyabilir."},{"t":"Su geçirmezlik","a":"Hidrofobik","d":"Lignin aynı zamanda hidrofobiktir, yani su geçirmezlik sağlar. Bu özellik özellikle ksilem ve sert kabuklarda önemlidir."}],"ans":"Lignin çepere sertlik, dayanıklılık ve su geçirmezlik kazandırır"},{"q":"Sklerenkima hücrelerinin neden olgun, büyümesi durmuş organlara uygun olduğunu adım adım açıklayalım.","steps":[{"t":"Sklerenkimanın sertliği","a":"Esnek değil","d":"Sklerenkima sert ve esnek olmayan bir dokudur. Bu yüzden bir organın uzamasına izin vermez."},{"t":"Olgun organın durumu","a":"Büyüme durmuş","d":"Olgun, büyümesi durmuş organlar artık uzamaz. Bu organlar için sert destek bir kısıtlama değil, avantajdır."},{"t":"Uyum","a":"Kalıcı destek","d":"Sklerenkima, büyümesi bitmiş organlara kalıcı ve dayanıklı destek verir. Genç organlarda olsaydı büyümeyi engellerdi."}],"ans":"Sert ve esnek olmadığından yalnızca büyümesi durmuş olgun organlara uygundur"},{"q":"Sklerenkima ve kollenkimanın işlevsel farkını ve hangi gelişim döneminde baskın olduklarını adım adım açıklayalım.","steps":[{"t":"Kollenkimanın işlevi","a":"Genç dönem esnek destek","d":"Kollenkima genç, büyüyen organlarda esnek destek sağlar. Canlı ve esnek olduğu için büyümeyi engellemez."},{"t":"Sklerenkimanın işlevi","a":"Olgun dönem sert destek","d":"Sklerenkima olgun, büyümesi durmuş organlarda sert ve kalıcı destek sağlar. Ölü ve ligninli olduğu için dayanıklıdır."},{"t":"İş bölümü","a":"Tamamlayıcı","d":"İki doku tamamlayıcı bir iş bölümü oluşturur. Kollenkima erken esnek destek, sklerenkima geç sert destek verir."}],"ans":"Kollenkima genç dönemde esnek, sklerenkima olgun dönemde sert destek verir"},{"q":"Sklerenkima liflerinin bitki gövdesindeki konumunu ve mekanik işlevini adım adım açıklayalım.","steps":[{"t":"Liflerin konumu","a":"İletim demeti çevresi","d":"Sklerenkima lifleri sıklıkla iletim demetlerinin çevresinde, başlık (şapka) hâlinde bulunur. Ayrıca floem ve ksilem ile ilişkili konumlanırlar."},{"t":"Demet hâlinde dizilim","a":"Eksenel destek","d":"Lifler uzun eksen boyunca demetler hâlinde dizilir. Bu dizilim gövdeye eksenel sağlamlık verir."},{"t":"Mekanik işlev","a":"Gerilme direnci","d":"Lifler özellikle gerilmeye karşı dayanıklıdır. Bu sayede gövde hem eğilmeye hem çekme kuvvetine direnç gösterir."}],"ans":"İletim demeti çevresinde demetler hâlinde, eksenel destek ve gerilme direnci sağlar"},{"q":"Sklereitlerin (taş hücreleri) bitkilerde nerelerde bulunduğunu ve işlevlerini adım adım açıklayalım.","steps":[{"t":"Meyve etinde","a":"Armut taneliliği","d":"Sklereitler armut gibi meyvelerin etinde dağınık olarak bulunur. Bu yüzden armut yenirken taneli bir his verir."},{"t":"Tohum kabuklarında","a":"Sert koruma","d":"Sert tohum ve çekirdek kabukları yoğun sklereitlerden oluşur. Bu hücreler tohumu mekanik zararlardan korur."},{"t":"İşlev","a":"Sertlik ve koruma","d":"Sklereitler bulundukları yere sertlik ve dayanıklılık katar. Hem destek hem koruma işlevi görürler."}],"ans":"Meyve etinde, sert kabuk ve tohum kabuklarında bulunup sertlik/koruma sağlar"},{"q":"Sklerenkima hücrelerinin geçit (por) yapısına sahip olmasını ve bunun anlamını adım adım açıklayalım.","steps":[{"t":"Çeperdeki geçitler","a":"İnce kalan bölgeler","d":"Sklerenkima çeperi çok kalın olsa da por (geçit) denen ince bölgeler bulunur. Bu bölgelerde çeper kalınlaşmamıştır."},{"t":"Gelişim sırasındaki işlevi","a":"Madde alışverişi","d":"Hücre canlıyken bu geçitler komşu hücrelerle madde alışverişini sağlar. Çeper kalınlaşırken bu noktalar açık kalır."},{"t":"Anlamı","a":"Eski canlılığın izi","d":"Geçitler, hücrenin bir zamanlar canlı olduğunun ve madde alışverişi yaptığının izidir. Olgunlukta hücre ölse de geçit yapısı kalır."}],"ans":"Geçitler ince çeper bölgeleridir; hücre canlıyken madde alışverişini sağlardı"},{"q":"Sklerenkima dokusunun enine kesitte tanınması için kullanılacak üç temel ölçütü adım adım belirleyelim.","steps":[{"t":"Birinci ölçüt","a":"Çok kalın çeper","d":"Hücrelerin çok kalın, düzgün kalınlaşmış çeperleri sklerenkimanın ilk işaretidir. Çeper genelde tüm yüzeyde kalındır."},{"t":"İkinci ölçüt","a":"Ölü, boş hücre","d":"Hücre içinin boş ve ölü olması ikinci ölçüttür. Bu özellik onu canlı kollenkimadan ayırır."},{"t":"Üçüncü ölçüt","a":"Lignin boyanması","d":"Lignin boyasıyla kırmızıya boyanma üçüncü ölçüttür. Bu üç ölçüt birlikte sklerenkimayı kesinleştirir."}],"ans":"Çok kalın düzgün çeper, ölü/boş hücre ve lignin boyanması"},{"q":"Sklerenkima çeperinin tüm yüzeyde düzgün kalınlaşmasının kollenkimadan farkını ve işlevsel anlamını adım adım açıklayalım.","steps":[{"t":"Sklerenkima kalınlaşması","a":"Düzgün, her yerde","d":"Sklerenkima çeperi tüm yüzeyde düzgün biçimde kalınlaşır. Bu, çepere her yönde sertlik kazandırır."},{"t":"Kollenkimadan farkı","a":"Düzensiz köşe","d":"Kollenkimada kalınlaşma düzensizdir, köşelerde yoğunlaşır. Bu fark mikroskopta iki dokuyu ayırmayı sağlar."},{"t":"İşlevsel anlam","a":"Sert, dayanıklı","d":"Düzgün ve her yönde kalın çeper, sklerenkimayı sert ve dayanıklı yapar. Bu, kalıcı ve güçlü destek için idealdir."}],"ans":"Sklerenkima düzgün/her yerde kalın (sert), kollenkima düzensiz/köşede kalındır (esnek)"},{"q":"Sklerenkima liflerinin bitki için hem mekanik hem ekonomik (insan kullanımı) önemini adım adım açıklayalım.","steps":[{"t":"Mekanik önem","a":"Gerilme direnci","d":"Sklerenkima lifleri bitkiye gerilmeye karşı dayanıklılık ve eksenel destek sağlar. Bu, gövdenin sağlam durmasını sağlar."},{"t":"Ekonomik önem","a":"Tekstil ve halat","d":"Keten, kenevir, jüt gibi bitkilerin lifleri tekstil, ip ve halat yapımında kullanılır. Bu lifler sklerenkima kökenlidir."},{"t":"Sonuç","a":"Çift değer","d":"Sklerenkima lifleri hem bitki için yapısal destek hem insan için değerli ham madde sağlar. Dayanıklılıkları bu iki işlevin temelidir."}],"ans":"Bitkide gerilme direnci, insan için tekstil/halat ham maddesi sağlar"},{"q":"Sklerenkimanın ksilem (odun borusu) ile ilişkisini ve odunsu bitkilerdeki destek rolünü adım adım açıklayalım.","steps":[{"t":"Ksilemin yapısı","a":"Ligninli iletim dokusu","d":"Ksilem su ileten ligninli hücrelerden oluşur. Ligninli çeperleri nedeniyle aynı zamanda destek de sağlar."},{"t":"Sklerenkima ile ortaklık","a":"Lignin ortak","d":"Sklerenkima ve ksilem çeperleri ligninle sertleştirilmiştir. Bu ortak özellik ikisini de mekanik desteğe katkı sağlar hâle getirir."},{"t":"Odunsu bitkide rol","a":"Asıl destek odun","d":"Odunsu bitkilerde asıl destek ligninli ksilem (odun) ve sklerenkima tarafından sağlanır. Bu yüzden ağaçlar çok ağır yük taşıyabilir."}],"ans":"Sklerenkima ve ligninli ksilem birlikte odunsu bitkilerin asıl desteğini oluşturur"},{"q":"Sklerenkima desteğinin neden su durumundan (turgordan) bağımsız olduğunu, kollenkimayla karşılaştırarak adım adım açıklayalım.","steps":[{"t":"Sklerenkima ölü hücre","a":"Protoplast yok","d":"Sklerenkima hücreleri ölüdür ve canlı protoplastı yoktur. Bu yüzden destekleri turgor basıncına bağlı değildir."},{"t":"Kollenkima canlı","a":"Turgora kısmen bağlı","d":"Kollenkima canlı olduğundan desteği kısmen turgora bağlıdır; su kaybında azalır. Bu bir zayıflıktır."},{"t":"Sonuç","a":"Kararlı destek","d":"Sklerenkima, ligninli sert çeperi sayesinde su durumuna bağlı olmadan kararlı destek verir. Bitki susuz kalsa bile bu destek korunur."}],"ans":"Ölü ve ligninli olduğundan sklerenkima desteği turgordan bağımsız ve kararlıdır"},{"q":"Sklerenkima hücrelerinin gelişiminde, çeperin lignifikasyonu (lignin birikimi) sürecini adım adım açıklayalım.","steps":[{"t":"Başlangıç çeperi","a":"Selülozlu birincil çeper","d":"Sklerenkima hücresi önce selülozlu birincil çepere sahiptir. Bu aşamada hücre canlı ve nispeten esnektir."},{"t":"İkincil çeper birikimi","a":"Kalın ikincil çeper","d":"Daha sonra selüloz ve hemiselülozdan kalın bir ikincil çeper birikir. Bu çeper hücreyi giderek kalınlaştırır."},{"t":"Lignifikasyon","a":"Lignin emdirilir","d":"Son aşamada çepere lignin emdirilir (lignifikasyon). Lignin sertlik sağlar ve protoplast ölünce sert ölü hücre kalır."}],"ans":"Birincil çeper, kalın ikincil çeper ve sonra lignin birikimiyle sert ölü hücre oluşur"},{"q":"Sklerenkimanın bitkiye sağladığı sertliğin, yatma (devrilme) ve hayvan ısırığına karşı korumadaki rolünü adım adım açıklayalım.","steps":[{"t":"Yatmaya karşı","a":"Dik durma","d":"Sklerenkima liflerinin sert desteği, gövdenin kendi ağırlığı ve yük altında devrilmesini önler. Bu, bitkinin dik kalmasını sağlar."},{"t":"Hayvan ısırığına karşı","a":"Sert engel","d":"Sklereitler ve lifler dokuyu sertleştirerek otçul hayvanların ısırmasını zorlaştırır. Sert kabuklar tohumu korur."},{"t":"Sonuç","a":"Mekanik savunma","d":"Sklerenkima hem yapısal destek hem mekanik savunma sağlar. Sertliği, bitkiyi hem fiziksel hem biyolojik baskılara karşı korur."}],"ans":"Sert destekle devrilmeyi önler ve sertliğiyle otçullara karşı koruma sağlar"}],"zor":[{"q":"Bir botanikçi enine kesitte içi boş, tüm yüzeyi düzgün kalınlaşmış ligninli çeperli, lignin boyasıyla kırmızıya boyanan ölü hücreler gözlemliyor. Bu dokuyu kanıtlarıyla belirleyip işlevini adım adım açıklayalım.","steps":[{"t":"Çeperin düzgün kalınlığı","a":"Her yerde kalın","d":"Çeperin tüm yüzeyde düzgün kalınlaşması sklerenkimanın işaretidir. Kollenkimada kalınlaşma köşelerde yoğunlaşırdı."},{"t":"Ölü hücre","a":"İçi boş","d":"Hücre içinin boş ve ölü olması, çeperin tamamen ligninleştiğini ve protoplastın yok olduğunu gösterir. Bu sklerenkimayı doğrular."},{"t":"Lignin boyanması","a":"Lignin kanıtı","d":"Lignin boyasıyla kırmızıya boyanma, çeperde lignin olduğunu kanıtlar. Bu, sklerenkimanın kesin göstergesidir."},{"t":"İşlev","a":"Sert, kalıcı destek","d":"Tüm bulgular sklerenkimanın olgun organa sert ve kalıcı destek verdiğini gösterir. Bu destek turgordan bağımsızdır."}],"ans":"Sklerenkima (ölü, düzgün ligninli çeper, sert ve kalıcı destek)"},{"q":"Bir öğrenci kollenkima ve sklerenkimanın aynı gövdede bulunduğunu gözlemliyor. İki dokunun çeper bileşimi, kalınlaşma deseni, canlılık ve işlevini adım adım karşılaştıralım.","steps":[{"t":"Çeper bileşimi","a":"Selüloz / lignin","d":"Kollenkima selülozca zengin, sklerenkima ligninli çepere sahiptir. Lignin sertlik, selüloz esneklik sağlar."},{"t":"Kalınlaşma deseni","a":"Köşe / düzgün","d":"Kollenkimada kalınlaşma köşelerde düzensiz, sklerenkimada tüm yüzeyde düzgündür. Bu desen mikroskopta ayırt edicidir."},{"t":"Canlılık","a":"Canlı / ölü","d":"Kollenkima olgunlukta canlı, sklerenkima ölüdür. Bu temel fizyolojik ayrımdır."},{"t":"İşlev","a":"Esnek / sert destek","d":"Kollenkima genç organa esnek, sklerenkima olgun organa sert destek verir. İkisi farklı gelişim dönemlerine hizmet eder."}],"ans":"Kollenkima selülozlu/köşe/canlı/esnek; sklerenkima ligninli/düzgün/ölü/sert"},{"q":"Bir araştırmacı, sert tohum kabuğunun çok sayıda kalın çeperli, izodiametrik, geçitli ölü hücreden oluştuğunu buluyor. Bu hücre tipini belirleyip koruma işleviyle ilişkisini adım adım açıklayalım.","steps":[{"t":"Hücre biçimi","a":"İzodiametrik, kısa","d":"Kısa, izodiametrik ve çok kalın çeperli hücreler sklereitlere (taş hücresi) işaret eder. Lifler ise uzun olurdu."},{"t":"Geçit yapısı","a":"Por kanalları","d":"Kalın çeperde uzun por (geçit) kanalları bulunması sklereitlerin tipik özelliğidir. Bu kanallar hücre canlıyken madde alışverişini sağlardı."},{"t":"Koruma işlevi","a":"Sert kabuk","d":"Yoğun sklereitler tohum kabuğunu çok sertleştirir. Bu sertlik tohumu mekanik hasara ve otçullara karşı korur."},{"t":"Sonuç","a":"Sklereit (koruma)","d":"Bu hücreler sklerenkimanın sklereit tipidir ve koruma amaçlı sertlik sağlar. Olgunlukta ölü oldukları için destekleri kalıcıdır."}],"ans":"Sklereitler (taş hücreleri); sert kabuk oluşturup tohumu korur"},{"q":"Bir araştırmacı, ligninleşmenin sklerenkima çeperini su geçirmez hâle getirdiğini ölçüyor. Bu özelliğin hem destek hem iletim açısından önemini adım adım açıklayalım.","steps":[{"t":"Ligninin hidrofobikliği","a":"Su geçirmez","d":"Lignin hidrofobik bir polimerdir ve çeperi su geçirmez yapar. Bu, suyun çeperden sızmasını engeller."},{"t":"Destek açısından","a":"Çeper dayanıklılığı","d":"Su geçirmez çeper, ıslanma ile bozulmaz ve mekanik dayanıklılığını korur. Bu, kalıcı destek için önemlidir."},{"t":"İletim açısından","a":"Ksilemde su taşıma","d":"Ligninli ksilem hücrelerinde su geçirmezlik, suyun boru içinde kalıp yana sızmadan taşınmasını sağlar. Lignin ayrıca boruların basınç altında çökmesini önler."},{"t":"Sonuç","a":"Destek + iletim","d":"Lignin hem sklerenkimaya kalıcı destek hem ksileme verimli su iletimi kazandırır. Su geçirmezlik bu iki işlevin ortak temelidir."}],"ans":"Lignin su geçirmezlik sağlar; bu hem kalıcı desteği hem ksilemde su iletimini kolaylaştırır"},{"q":"Bir bitki gelişim sürecinde organ önce uzar sonra olgunlaşır; bu sırada destek dokuları değişir. Kollenkimadan sklerenkimaya geçişi gelişimsel ve mekanik mantıkla adım adım açıklayalım.","steps":[{"t":"Uzama dönemi","a":"Esnek destek gerekir","d":"Organ uzarken esnek desteğe ihtiyaç vardır. Bu dönemde canlı, plastik çeperli kollenkima baskındır çünkü uzamayı engellemez."},{"t":"Olgunlaşma dönemi","a":"Kalıcı sert destek","d":"Organ olgunlaşıp büyümesi durunca kalıcı, sert desteğe ihtiyaç doğar. Bunu ligninli, ölü sklerenkima sağlar."},{"t":"Mekanik mantık","a":"Esneklik → dayanıklılık","d":"Geçiş, mekanik önceliklerin değişmesini yansıtır: önce esneklik (büyüme için), sonra dayanıklılık (kalıcı yapı için). Bu, kaynakların verimli kullanılmasını sağlar."},{"t":"Sonuç","a":"Tamamlayıcı sistem","d":"Kollenkima ve sklerenkima zaman içinde tamamlayıcı bir destek sistemi oluşturur. Her biri gelişimin farklı bir evresine optimize olmuştur."}],"ans":"Uzamada esnek kollenkima, olgunlukta kalıcı sert sklerenkima baskın olur"},{"q":"Bir laboratuvarda iki destek dokusuna floroglusinol-HCl (lignin) testi uygulanıyor; biri parlak kırmızıya boyanıyor, diğeri boyanmıyor. Boyanan dokuyu kanıtlarıyla belirleyip kollenkimanın neden boyanmadığını adım adım açıklayalım.","steps":[{"t":"Test prensibi","a":"Lignini gösterir","d":"Floroglusinol-HCl testi, çeperdeki lignin ile reaksiyona girip parlak kırmızı renk verir. Boyanma, ligninin varlığını kanıtlar."},{"t":"Boyanan doku","a":"Sklerenkima","d":"Parlak kırmızıya boyanan doku lignin içerir, yani sklerenkimadır. Sklerenkima çeperleri ligninle kalınlaşmıştır."},{"t":"Boyanmayan doku","a":"Kollenkima","d":"Boyanmayan doku lignin içermez. Kollenkima çeperi selülozca zengindir ve ligninleşmez."},{"t":"Boyanmama nedeni","a":"Selülozlu çeper","d":"Kollenkima selülozlu çeperi nedeniyle floroglusinol ile reaksiyon vermez. Bu da onun esnek ve canlı kalmasını açıklar."}],"ans":"Boyanan sklerenkimadır; kollenkima ligninsiz selülozlu çeper nedeniyle boyanmaz"},{"q":"Bir mühendis, sklerenkima liflerinin yüksek çekme dayanımına sahip olduğunu ölçüyor. Bu mekanik özelliği lif geometrisi ve çeper yapısıyla adım adım açıklayalım.","steps":[{"t":"Lif geometrisi","a":"Uzun, ince, sivri","d":"Sklerenkima lifleri uzun, ince ve sivri uçludur, üst üste binerek dizilir. Bu geometri yükü eksen boyunca taşımaya uygundur."},{"t":"İkincil çeper","a":"Kalın, tabakalı","d":"Liflerin kalın ikincil çeperi selüloz mikrofibrilleriyle tabakalı şekilde örülüdür. Mikrofibril yönelimi çekme dayanımını artırır."},{"t":"Lignin katkısı","a":"Sıkışma direnci","d":"Lignin çeperde mikrofibriller arasını doldurarak sıkışmaya ve kaymaya direnç verir. Selüloz çekmeye, lignin sıkışmaya dayanır."},{"t":"Sonuç","a":"Yüksek çekme dayanımı","d":"Uzun geometri, tabakalı selüloz ve lignin birlikte yüksek çekme dayanımı sağlar. Bu yüzden lifler halat ve tekstilde kullanılır."}],"ans":"Uzun geometri + tabakalı selüloz + lignin birleşince lif yüksek çekme dayanımı kazanır"},{"q":"Bir kesitte iki bitişik destek bölgesi var: dış bölge canlı/köşe kalınlaşmalı, iç bölge ölü/düzgün ligninli. Her bölgeyi tanımlayıp gelişimsel sırayı ve işlevsel iş bölümünü adım adım açıklayalım.","steps":[{"t":"Dış bölge","a":"Kollenkima","d":"Canlı ve köşeleri kalınlaşmış dış bölge kollenkimadır. Selülozlu çeperiyle esnek destek sağlar."},{"t":"İç bölge","a":"Sklerenkima","d":"Ölü ve tüm yüzeyi düzgün ligninli iç bölge sklerenkimadır. Ligninli çeperiyle sert, kalıcı destek verir."},{"t":"Gelişimsel sıra","a":"Önce kollenkima","d":"Genç organda önce esnek kollenkima farklılaşır; organ olgunlaşınca sklerenkima eklenir. Bu sıra büyüme-dayanıklılık dengesini yansıtır."},{"t":"İş bölümü","a":"Esneklik + dayanıklılık","d":"Kollenkima dinamik/esnek destek, sklerenkima statik/sert destek sağlar. İkisi birlikte bitkinin tam destek sistemini kurar."}],"ans":"Dış: kollenkima (esnek), iç: sklerenkima (sert); önce kollenkima, sonra sklerenkima gelişir"},{"q":"Bir araştırmacı, sklerenkima desteğinin turgor basıncından bağımsız olduğunu ama kollenkima desteğinin su kaybında azaldığını gözlemliyor. Bu farkı hücre yapısı temelinde adım adım açıklayalım.","steps":[{"t":"Sklerenkimanın yapısı","a":"Ölü, ligninli","d":"Sklerenkima hücreleri ölüdür ve sert ligninli çepere sahiptir. Desteği tamamen çeperin mekanik dayanıklılığından gelir."},{"t":"Turgordan bağımsızlık","a":"Canlı protoplast yok","d":"Sklerenkimada canlı protoplast olmadığından turgor basıncına ihtiyaç yoktur. Bu yüzden su kaybı desteği etkilemez."},{"t":"Kollenkimanın bağımlılığı","a":"Canlı, turgorlu","d":"Kollenkima canlı olduğundan desteği kısmen hücre turgoruna bağlıdır. Su kaybedince turgor düşer ve destek azalır."},{"t":"Sonuç","a":"Kararlı / değişken","d":"Sklerenkima desteği kararlıyken kollenkima desteği su durumuna göre değişir. Bu fark, otsu bitkilerin susuzlukta pörsümesini açıklar."}],"ans":"Sklerenkima ölü/ligninli olduğundan turgordan bağımsız; kollenkima canlı olduğundan su kaybında zayıflar"},{"q":"Bir öğrenci, sklerenkima çeperinde uzun, dallı por (geçit) kanalları görüyor. Bu kanalların hücre gelişimindeki anlamını ve neden hâlâ var olduğunu adım adım açıklayalım.","steps":[{"t":"Por kanalları","a":"İnce çeper noktaları","d":"Por (geçit) kanalları, kalın çeperde ince kalan ve komşu hücreyle hizalanan bölgelerdir. Sklereitlerde bunlar uzun ve dallı görünür."},{"t":"Canlı dönemdeki işlevi","a":"Madde alışverişi","d":"Hücre canlıyken bu geçitler plazmodezmalar aracılığıyla komşu hücrelerle madde alışverişini sağlardı. Çeper kalınlaşırken bu noktalar açık bırakıldı."},{"t":"Olgunlukta kalması","a":"Yapısal iz","d":"Hücre olgunlukta ölse de geçit yapısı çeperde kalıcı bir iz olarak kalır. Çünkü çeper canlı olmasa da fiziksel yapısını korur."},{"t":"Sonuç","a":"Gelişim kanıtı","d":"Por kanalları, hücrenin bir zamanlar canlı ve aktif olduğunun kanıtıdır. Olgun ölü hücrede bile gelişim geçmişini yansıtır."}],"ans":"Por kanalları canlı dönemde madde alışverişi sağlardı; ölü hücrede yapısal iz olarak kalır"},{"q":"Bir mühendis, bitki gövdesini bir kompozit malzemeye benzetiyor: esnek bir matris içinde sert lifler. Bu analojide kollenkima ve sklerenkimanın rolünü adım adım açıklayalım.","steps":[{"t":"Kompozit malzeme mantığı","a":"Matris + lif","d":"Kompozit malzemeler, esnek bir matris ile sert lifleri birleştirir. Böylece hem esneklik hem dayanıklılık elde edilir."},{"t":"Kollenkimanın rolü","a":"Esnek matris","d":"Kollenkima esnek ve canlı bir destek sağlar, esnek matrise benzer. Eğilmeyi tolere eder ve enerji emer."},{"t":"Sklerenkimanın rolü","a":"Sert lif","d":"Sklerenkima lifleri sert ve çekmeye dayanıklıdır, kompozitteki sert liflere benzer. Yapısal yükü ve gerilmeyi taşır."},{"t":"Sonuç","a":"Hem esnek hem güçlü","d":"İki dokunun birleşimi, gövdeyi hem esnek hem güçlü yapan bir biyolojik kompozit oluşturur. Bu, kırılmadan eğilme yeteneğinin temelidir."}],"ans":"Kollenkima esnek matris, sklerenkima sert lif rolü oynar; birlikte biyolojik kompozit oluşturur"},{"q":"Bir araştırmacı, sklerenkimanın bazı bitkilerde iletim demetlerinin çevresinde demet kını (kılıfı) oluşturduğunu buluyor. Bu konumun mekanik ve koruyucu işlevini adım adım açıklayalım.","steps":[{"t":"Demet kını konumu","a":"Demet çevresinde halka","d":"Sklerenkima lifleri iletim demetinin etrafını bir kın (kılıf) gibi sarabilir. Bu konum demeti dıştan kuşatır."},{"t":"Mekanik işlev","a":"Demet desteği","d":"Kın, iletim demetine mekanik destek sağlar ve onu eğilme/sıkışmaya karşı güçlendirir. Böylece demet gövde hareketinde korunur."},{"t":"Koruyucu işlev","a":"Hassas dokuyu korur","d":"Floem gibi hassas iletim dokuları sert kınla mekanik hasara karşı korunur. Sert sklerenkima bir zırh görevi görür."},{"t":"Sonuç","a":"Destek + koruma","d":"Demet kını hem mekanik destek hem koruma sağlar. Sklerenkimanın sertliği bu iki işlevi mümkün kılar."}],"ans":"Demet kını iletim demetine mekanik destek ve hassas dokuya koruma sağlar"},{"q":"Bir bilim insanı, odunsu ve otsu bitkilerin destek stratejilerini karşılaştırıyor. Sklerenkima ve kollenkimanın bu iki bitki tipindeki ağırlığını adım adım açıklayalım.","steps":[{"t":"Otsu bitki stratejisi","a":"Turgor + kollenkima","d":"Otsu bitkilerde odun azdır; destek büyük ölçüde turgor basıncı ve esnek kollenkimadan gelir. Bu yüzden su kaybında pörsürler."},{"t":"Odunsu bitki stratejisi","a":"Lignin + sklerenkima/odun","d":"Odunsu bitkilerde destek ligninli ksilem (odun) ve sklerenkimadan gelir. Bu sert, kalıcı destek ağır yükleri taşır."},{"t":"Karşılaştırma","a":"Esnek / sert ağırlık","d":"Otsu bitkide esnek/canlı destek (kollenkima, turgor), odunsu bitkide sert/ölü destek (sklerenkima, odun) ağır basar. Strateji bitkinin boyutu ve ömrüyle ilişkilidir."},{"t":"Sonuç","a":"Boyuta uyarlı destek","d":"Küçük/kısa ömürlü otsu bitkiler esnek desteğe, büyük/uzun ömürlü odunsu bitkiler sert desteğe yatırım yapar. Sklerenkima büyük yapıların kalıcı desteğinin anahtarıdır."}],"ans":"Otsu bitkide kollenkima/turgor, odunsu bitkide sklerenkima/odun desteği baskındır"},{"q":"Bir araştırmacı, sklerenkima hücrelerinin programlı hücre ölümü (apoptoz benzeri) ile olgunlaştığını öğreniyor. Bu olgunlaşma sürecinin destek işlevi için neden gerekli olduğunu adım adım açıklayalım.","steps":[{"t":"Programlı ölüm","a":"Kontrollü hücre ölümü","d":"Sklerenkima hücreleri olgunlaşırken programlı bir biçimde ölür. Bu, rastgele bir bozulma değil, kontrollü bir gelişim adımıdır."},{"t":"Protoplastın ortadan kalkması","a":"İç boşluk açılır","d":"Hücre ölünce protoplast kaybolur ve geriye sert ligninli çeper kalır. İç boşluk, hücreyi hafif ama dayanıklı yapar."},{"t":"Destek için gerekliliği","a":"Saf yapısal çeper","d":"Ölü hücre, metabolik bakım gerektirmeyen saf yapısal bir destek elemanı hâline gelir. Canlı kalsaydı sürekli enerji harcanması gerekirdi."},{"t":"Sonuç","a":"Verimli kalıcı destek","d":"Programlı ölüm, sklerenkimayı verimli, kalıcı ve turgordan bağımsız bir destek elemanına dönüştürür. Bu, olgun yapıların ekonomik desteği için idealdir."}],"ans":"Programlı ölümle protoplast kaybolur; geriye bakım gerektirmeyen sert ligninli çeper kalır"},{"q":"Bir öğrenci, kollenkima ve sklerenkimanın hangi mekanik koşullarda ve hangi gelişim evrelerinde avantajlı olduğunu karşılaştırıyor. İki dokunun işlevsel iş bölümünü kapsamlı biçimde adım adım açıklayalım.","steps":[{"t":"Kollenkima koşulu","a":"Genç/dinamik","d":"Kollenkima genç, büyüyen organlarda ve dinamik (eğilme) koşullarında avantajlıdır. Esnekliği büyümeyi engellemez ve eğilme stresini emer."},{"t":"Sklerenkima koşulu","a":"Olgun/statik","d":"Sklerenkima olgun, büyümesi durmuş organlarda ve statik ağır yük koşullarında avantajlıdır. Sertliği kalıcı ve dayanıklı destek sağlar."},{"t":"Çeper farkı","a":"Selüloz / lignin","d":"Bu işlevsel fark çeper bileşiminden kaynaklanır: selülozlu kollenkima esnek, ligninli sklerenkima serttir. Madde yapısı işlevi belirler."},{"t":"İş bölümü","a":"Bütüncül destek","d":"İki doku, gelişim ve mekanik koşullara göre iş bölümü yapar: erken/dinamik destek kollenkima, geç/statik destek sklerenkima. Birlikte bitkinin bütüncül destek sistemini oluştururlar."}],"ans":"Kollenkima genç/dinamik esnek destek, sklerenkima olgun/statik sert destek verir; tamamlayıcıdırlar"}]}}};
